import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameState, Player, CardData, GamePhase, GameMode } from './types';
import { createDeck, getRoundScores, calculateHandValue, decideBotAction, shuffleDeck } from './services/gameLogic';
import { createRoom, joinRoom, subscribeToRoom, updateGameState, getRoomData, resetRoomToLobby } from './services/online';
import { DEFAULT_TOTAL_ROUNDS } from './constants';
import Card from './components/Card';
import Auth from './components/Auth';
import { supabase, signOut } from './services/supabase';
import { RefreshCw, Trophy, Users, AlertCircle, Hand, ChevronRight, EyeOff, Eye, User, Bot, ArrowRight, ChevronLeft, Play, Hash, Sparkles, LogOut, Globe, Wifi, Copy, CloudUpload, Lock, Edit2, Check, Loader2, Info, X } from 'lucide-react';

const SESSION_KEY = 'TRI_STACK_SESSION';
const NAME_KEY = 'TRI_STACK_PLAYER_NAME';
const TUTORIAL_KEY = 'TRI_STACK_TUTORIAL_COMPLETE_V4'; // Versioned key

const App: React.FC = () => {
  // --- Auth State ---
  const [session, setSession] = useState<any>(null);
  const [isGuest, setIsGuest] = useState(false);
  const [authLoading, setAuthLoading] = useState(true);

  // --- Tutorial State ---
  const [hasSeenTutorial, setHasSeenTutorial] = useState<boolean>(() => {
    return localStorage.getItem(TUTORIAL_KEY) === 'true';
  });
  const [tutorialStep, setTutorialStep] = useState(0);

  // --- Game State ---
  const [gameState, setGameState] = useState<GameState>({
    gameMode: null,
    deck: [],
    openDeck: [],
    players: [],
    currentPlayerIndex: 0,
    roundJoker: null,
    roundNumber: 1,
    totalRounds: DEFAULT_TOTAL_ROUNDS,
    phase: GamePhase.SETUP,
    turnLog: [],
    winner: null,
    lastDiscardedId: null,
    tossedThisTurn: false,
    pendingDiscard: null,
    pendingToss: [],
    playerNames: []
  });

  const [selectedCardIds, setSelectedCardIds] = useState<string[]>([]);
  const [isTransitioning, setIsTransitioning] = useState(false);

  // Menu State
  const [showMultiplayerSelection, setShowMultiplayerSelection] = useState(false);
  const [showOnlineSelection, setShowOnlineSelection] = useState(false); 
  const [showRoundSelectionSP, setShowRoundSelectionSP] = useState(false);
  const [setupPlayerCount, setSetupPlayerCount] = useState(4);
  const [selectedTotalRounds, setSelectedTotalRounds] = useState(DEFAULT_TOTAL_ROUNDS);
  const [isNameEntryStep, setIsNameEntryStep] = useState(false);
  const [customPlayerNames, setCustomPlayerNames] = useState<string[]>([]);

  // User Customization
  const [customDisplayName, setCustomDisplayName] = useState('');
  const [isEditingName, setIsEditingName] = useState(false);

  // Online Specific State
  const [roomCode, setRoomCode] = useState('');
  const [joinCodeInput, setJoinCodeInput] = useState('');
  const [myOnlineId, setMyOnlineId] = useState<number | null>(null); 
  const [onlineLobbyPlayers, setOnlineLobbyPlayers] = useState<{id: number, name: string}[]>([]);
  const [isOnlineLobby, setIsOnlineLobby] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false); 
  const [isReconnecting, setIsReconnecting] = useState(false); 
  const [isJoining, setIsJoining] = useState(false); 

  // Exit Confirmation State
  const [showExitConfirm, setShowExitConfirm] = useState(false);

  // --- Auth Effect ---
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setAuthLoading(false);
    }).catch((err) => {
      console.warn("Supabase auth check failed:", err);
      setAuthLoading(false);
    });

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    return () => subscription.unsubscribe();
  }, []);

  // --- Load Custom Name ---
  useEffect(() => {
    const savedName = localStorage.getItem(NAME_KEY);
    if (savedName) setCustomDisplayName(savedName);
  }, []);

  const getDisplayName = () => {
    if (customDisplayName) return customDisplayName;
    return isGuest ? 'Guest' : (session?.user?.email?.split('@')[0] || 'Player');
  };

  const saveCustomName = () => {
    if (customDisplayName.trim()) {
      localStorage.setItem(NAME_KEY, customDisplayName);
      setIsEditingName(false);
    }
  };

  // --- Tutorial Logic Helpers ---
  const skipTutorial = () => {
    setTutorialStep(0);
    setHasSeenTutorial(true);
    localStorage.setItem(TUTORIAL_KEY, 'true');
  };

  const advanceTutorial = () => {
    if (tutorialStep === 5) {
      skipTutorial();
    } else {
      setTutorialStep(prev => prev + 1);
    }
  };

  // Auto-advance tutorial based on in-game actions
  useEffect(() => {
    if (tutorialStep === 2 && selectedCardIds.length > 0) {
      setTutorialStep(3);
    }
    if (tutorialStep === 3 && gameState.phase === GamePhase.PLAYER_DRAW) {
      setTutorialStep(4);
    }
    // Advance to final step once turn finishes and returns to start phase for next check
    if (tutorialStep === 4 && gameState.phase === GamePhase.PLAYER_TURN_START && gameState.currentPlayerIndex !== 0) {
      setTutorialStep(5);
    }
  }, [tutorialStep, selectedCardIds, gameState.phase, gameState.currentPlayerIndex]);

  // --- Reconnection Logic ---
  useEffect(() => {
    const checkSession = async () => {
      const savedSession = localStorage.getItem(SESSION_KEY);
      if (savedSession) {
        try {
          setIsReconnecting(true);
          const { code, playerId } = JSON.parse(savedSession);
          const { data: roomData, error } = await getRoomData(code);

          if (error || !roomData) {
             localStorage.removeItem(SESSION_KEY);
             setIsReconnecting(false);
             return;
          }

          setRoomCode(code);
          setMyOnlineId(playerId);
          setIsGuest(true);

          if (roomData.status === 'WAITING') {
            setOnlineLobbyPlayers(roomData.players || []);
            setIsOnlineLobby(true);
            setGameState(prev => ({ ...prev, gameMode: (playerId === 0 ? 'ONLINE_HOST' : 'ONLINE_CLIENT') as GameMode }));
          } else {
             if (roomData.game_state) {
               const effectiveMode = (playerId === 0 ? 'ONLINE_HOST' : 'ONLINE_CLIENT') as GameMode;
               setGameState({ ...roomData.game_state, gameMode: effectiveMode });
               setIsOnlineLobby(false);
             }
          }
        } catch (e) {
          localStorage.removeItem(SESSION_KEY);
        } finally {
          setIsReconnecting(false);
        }
      }
    };
    checkSession();
  }, []);

  // --- Online Subscription Effect ---
  useEffect(() => {
    if (!roomCode) return;
    const subscription = subscribeToRoom(roomCode, (roomData) => {
      if (roomData.status === 'WAITING') {
         setOnlineLobbyPlayers(roomData.players || []);
         if (!isOnlineLobby && gameState.gameMode) {
            setIsOnlineLobby(true);
            const mode = myOnlineId === 0 ? 'ONLINE_HOST' : 'ONLINE_CLIENT';
            setGameState(prev => ({ ...prev, gameMode: mode as GameMode }));
         }
      }
      else if (roomData.status === 'PLAYING' || roomData.status === 'FINISHED') {
         if (roomData.game_state) {
           const effectiveMode = (myOnlineId === 0 ? 'ONLINE_HOST' : 'ONLINE_CLIENT') as GameMode;
           setGameState({ ...roomData.game_state, gameMode: effectiveMode });
           setIsOnlineLobby(false); 
           setIsNameEntryStep(false); 
           setShowOnlineSelection(false); 
           setIsSyncing(false); 
         }
      }
    });
    return () => { supabase.removeChannel(subscription); };
  }, [roomCode, myOnlineId, isOnlineLobby, gameState.gameMode]);

  const syncOnlineState = async (newState: GameState) => {
    if ((gameState.gameMode === 'ONLINE_HOST' || gameState.gameMode === 'ONLINE_CLIENT') && roomCode) {
       setIsSyncing(true);
       await updateGameState(roomCode, newState);
    }
  };

  const saveSession = (code: string, playerId: number) => {
    localStorage.setItem(SESSION_KEY, JSON.stringify({ code, playerId }));
  };

  const clearSession = () => {
    if (gameState.gameMode === 'ONLINE_HOST' || gameState.gameMode === 'ONLINE_CLIENT' || roomCode) {
       if (myOnlineId !== null && roomCode) {
          import('./services/online').then(({ leaveRoom }) => {
             leaveRoom(roomCode, myOnlineId!);
          });
       }
    }
    localStorage.removeItem(SESSION_KEY);
    setRoomCode('');
    setMyOnlineId(null);
    setOnlineLobbyPlayers([]);
    setIsOnlineLobby(false);
    setGameState({
      gameMode: null,
      deck: [],
      openDeck: [],
      players: [],
      currentPlayerIndex: 0,
      roundJoker: null,
      roundNumber: 1,
      totalRounds: DEFAULT_TOTAL_ROUNDS,
      phase: GamePhase.SETUP,
      turnLog: [],
      winner: null,
      lastDiscardedId: null,
      tossedThisTurn: false,
      pendingDiscard: null,
      pendingToss: [],
      playerNames: []
    });
    setSelectedCardIds([]);
    setIsTransitioning(false);
    setIsNameEntryStep(false);
    setShowMultiplayerSelection(false);
    setShowOnlineSelection(false);
    setShowRoundSelectionSP(false);
    setShowExitConfirm(false);
    setIsSyncing(false);
    setIsReconnecting(false);
    setIsJoining(false);
  };

  const handleSignOut = () => { clearSession(); signOut(); };

  const currentPlayer = gameState.players[gameState.currentPlayerIndex] || { id: -1, name: 'Loading', isBot: false, hand: [], score: 0, totalScore: 0, lastAction: '' };

  let bottomPlayer = currentPlayer;
  let opponentsToRender = gameState.players.filter(p => p.id !== currentPlayer.id);

  if (gameState.gameMode === 'SINGLE_PLAYER' && gameState.players.length > 0) {
    bottomPlayer = gameState.players[0]; 
    opponentsToRender = gameState.players.filter(p => p.id !== 0); 
  } else if ((gameState.gameMode === 'ONLINE_HOST' || gameState.gameMode === 'ONLINE_CLIENT') && myOnlineId !== null) {
    bottomPlayer = gameState.players.find(p => p.id === myOnlineId) || currentPlayer;
    opponentsToRender = gameState.players.filter(p => p.id !== myOnlineId);
  }

  const isMyTurnOnline = (gameState.gameMode === 'ONLINE_HOST' || gameState.gameMode === 'ONLINE_CLIENT') 
      ? currentPlayer.id === myOnlineId 
      : true; 

  const isPlayerTurn = !isTransitioning 
      && !currentPlayer.isBot 
      && gameState.phase !== GamePhase.ROUND_END 
      && gameState.phase !== GamePhase.MATCH_END
      && isMyTurnOnline; 

  const isBotThinking = gameState.gameMode === 'SINGLE_PLAYER' && currentPlayer.isBot && !isTransitioning && gameState.phase !== GamePhase.ROUND_END;

  // --- ONLINE SETUP ---
  const handleCreateOnlineGame = async () => {
    const hostName = getDisplayName();
    const { code, error } = await createRoom(hostName, session?.user?.id || 'guest');
    if (error) {
      alert("Error creating room: " + (error.message || 'Check your connection'));
      return;
    }
    setRoomCode(code);
    setMyOnlineId(0); 
    saveSession(code, 0); 
    setOnlineLobbyPlayers([{ id: 0, name: hostName }]);
    setIsOnlineLobby(true);
    setGameState(prev => ({ ...prev, gameMode: 'ONLINE_HOST' })); 
    setSelectedTotalRounds(5);
  };

  const handleJoinOnlineGame = async () => {
    if (isJoining) return; 
    if (joinCodeInput.length !== 4) return alert("Enter a 4-letter code");
    setIsJoining(true);
    const myName = getDisplayName();
    const { success, error, playerId, players } = await joinRoom(joinCodeInput.toUpperCase(), myName);
    if (!success) {
      alert(error);
      setIsJoining(false);
      return;
    }
    const code = joinCodeInput.toUpperCase();
    setRoomCode(code);
    setMyOnlineId(playerId!);
    saveSession(code, playerId!); 
    setOnlineLobbyPlayers(players!);
    setIsOnlineLobby(true);
    setGameState(prev => ({ ...prev, gameMode: 'ONLINE_CLIENT' }));
    setIsJoining(false);
  };

  const startOnlineGame = () => {
     if (onlineLobbyPlayers.length < 2) return;
     const players: Player[] = onlineLobbyPlayers.map(p => ({
        id: p.id, name: p.name, isBot: false, hand: [], score: 0, totalScore: 0, lastAction: 'Joined'
     }));
     startRound(1, players, 'ONLINE_HOST');
  };

  // --- LOCAL SETUP FLOWS ---
  const openSinglePlayerSetup = () => {
    setShowRoundSelectionSP(true);
    setSelectedTotalRounds(5);
  };

  const startSinglePlayerMatch = (rounds: number) => {
    setSelectedTotalRounds(rounds);
    const playerName = getDisplayName();
    const names = [playerName, 'Bot Alpha', 'Bot Beta', 'Bot Gamma'];
    setGameState(prev => ({
      ...prev,
      gameMode: 'SINGLE_PLAYER',
      playerNames: names,
      phase: GamePhase.SETUP
    }));
    setShowRoundSelectionSP(false);

    // Check for tutorial
    if (!hasSeenTutorial) {
      setTutorialStep(1);
    }
  };

  const initMultiplayerSetup = (count: number) => {
    setSetupPlayerCount(count);
    setSelectedTotalRounds(5);
    setCustomPlayerNames(Array.from({ length: count }, (_, i) => `Player ${i + 1}`));
    setIsNameEntryStep(true);
  };

  const finalizeMultiplayerStart = () => {
    setGameState(prev => ({
      ...prev,
      gameMode: 'MULTIPLAYER',
      playerNames: customPlayerNames,
      phase: GamePhase.SETUP
    }));
    setIsNameEntryStep(false);
  };

  // --- Game Loop: Start Round ---
  const startRound = useCallback((roundNum: number, existingPlayers?: Player[], mode?: GameMode) => {
    const newDeck = createDeck();
    const jokerIndex = Math.floor(Math.random() * newDeck.length);
    const roundJoker = { ...newDeck[jokerIndex] };
    let players: Player[] = [];
    let startingPlayerIndex = 0; 

    if (existingPlayers) {
      const caller = existingPlayers.find(p => p.wasCaller);
      if (caller) startingPlayerIndex = caller.id;
      players = existingPlayers.map(p => ({ 
        ...p, hand: [], score: 0, totalScore: p.totalScore || 0, lastAction: 'Waiting...', wasCaller: false 
      }));
    } else {
      if (mode === 'SINGLE_PLAYER') {
        const names = gameState.playerNames.length > 0 ? gameState.playerNames : ['You', 'Bot Alpha', 'Bot Beta', 'Bot Gamma'];
        players = [
          { id: 0, name: names[0], isBot: false, hand: [], score: 0, totalScore: 0, lastAction: 'Waiting...' },
          { id: 1, name: names[1], isBot: true, hand: [], score: 0, totalScore: 0, lastAction: 'Waiting...' },
          { id: 2, name: names[2], isBot: true, hand: [], score: 0, totalScore: 0, lastAction: 'Waiting...' },
          { id: 3, name: names[3], isBot: true, hand: [], score: 0, totalScore: 0, lastAction: 'Waiting...' }
        ];
      } else if (mode === 'MULTIPLAYER') {
        const count = setupPlayerCount > 0 ? setupPlayerCount : 4;
        const names = gameState.playerNames.length > 0 ? gameState.playerNames : Array.from({ length: count }, (_, i) => `Player ${i + 1}`);
        players = Array.from({ length: count }, (_, i) => ({
          id: i, name: names[i], isBot: false, hand: [], score: 0, totalScore: 0, lastAction: 'Waiting...'
        }));
      }
    }

    players.forEach(p => { p.hand = newDeck.splice(0, 3); });

    const newState: GameState = {
      ...gameState, 
      deck: newDeck,
      openDeck: [],
      players,
      currentPlayerIndex: startingPlayerIndex, 
      roundJoker,
      roundNumber: roundNum,
      totalRounds: selectedTotalRounds,
      phase: GamePhase.PLAYER_TURN_START,
      turnLog: [],
      winner: null,
      lastDiscardedId: null,
      tossedThisTurn: false,
      pendingDiscard: null,
      pendingToss: [],
      gameMode: (mode || gameState.gameMode) as GameMode 
    };

    setGameState(newState);
    if (mode === 'ONLINE_HOST' || gameState.gameMode === 'ONLINE_HOST') { updateGameState(roomCode, newState); }
    setSelectedCardIds([]);
    setIsTransitioning(mode === 'MULTIPLAYER' || (existingPlayers && gameState.gameMode === 'MULTIPLAYER'));
  }, [gameState.gameMode, setupPlayerCount, gameState.playerNames, selectedTotalRounds, roomCode, gameState]);

  useEffect(() => {
    if (gameState.phase === GamePhase.SETUP && gameState.gameMode && gameState.gameMode !== 'ONLINE_HOST' && gameState.gameMode !== 'ONLINE_CLIENT') {
      startRound(1, undefined, gameState.gameMode);
    }
  }, [gameState.phase, gameState.gameMode, startRound]);


  // --- BOT LOGIC ---
  useEffect(() => {
    if (!isBotThinking) return;
    const timeout = setTimeout(() => {
      const p = currentPlayer;
      let newState = { ...gameState };
      if (gameState.phase === GamePhase.PLAYER_TURN_START) {
        const action = decideBotAction(p, gameState.roundJoker, gameState.tossedThisTurn);
        if (action.type === 'SHOW') {
           const results = getRoundScores(gameState.players, gameState.currentPlayerIndex, gameState.roundJoker);
           const updatedPlayers = gameState.players.map(pl => {
             const roundRes = results.find(r => r.playerId === pl.id);
             return { 
                ...pl, score: roundRes?.roundScore || 0, totalScore: (pl.totalScore || 0) + (roundRes?.roundScore || 0), wasCaller: pl.id === p.id 
             };
           });
           newState = { ...newState, players: updatedPlayers, phase: GamePhase.ROUND_END };
        } else if (action.type === 'TOSS' && action.cardIds) {
          const tossedCards = p.hand.filter(c => action.cardIds?.includes(c.id));
          const newHand = p.hand.filter(c => !action.cardIds?.includes(c.id));
          newState = {
            ...newState, players: newState.players.map(pl => pl.id === p.id ? { ...pl, hand: newHand } : pl), pendingToss: tossedCards, phase: GamePhase.PLAYER_TOSSING_DRAW, tossedThisTurn: true
          };
        } else if (action.type === 'DISCARD' && action.cardIds) {
          const cardToDiscard = p.hand.find(c => c.id === action.cardIds![0])!;
          const newHand = p.hand.filter(c => c.id !== cardToDiscard.id);
          newState = {
            ...newState, players: newState.players.map(pl => pl.id === p.id ? { ...pl, hand: newHand } : pl), pendingDiscard: cardToDiscard, lastDiscardedId: cardToDiscard.id, phase: GamePhase.PLAYER_DRAW
          };
        }
      } 
      else if (gameState.phase === GamePhase.PLAYER_DRAW || gameState.phase === GamePhase.PLAYER_TOSSING_DRAW) {
        let deckToDrawFrom = newState.deck;
        let openDeckForRecycle = newState.openDeck;
        if (deckToDrawFrom.length === 0) {
           if (openDeckForRecycle.length > 1) {
              const topCard = openDeckForRecycle.pop()!;
              const recycled = shuffleDeck([...openDeckForRecycle]);
              deckToDrawFrom = recycled;
              openDeckForRecycle = [topCard];
              newState.deck = deckToDrawFrom; newState.openDeck = openDeckForRecycle;
           } else { return; }
        }
        const drawn = newState.deck.shift()!;
        newState.players = newState.players.map(pl => pl.id === p.id ? { ...pl, hand: [...pl.hand, drawn] } : pl);
        if (newState.pendingToss.length) newState.openDeck = [...newState.openDeck, ...newState.pendingToss];
        if (newState.pendingDiscard) newState.openDeck = [...newState.openDeck, newState.pendingDiscard];
        newState.pendingToss = []; newState.pendingDiscard = null;
        newState.currentPlayerIndex = (newState.currentPlayerIndex + 1) % newState.players.length;
        newState.phase = GamePhase.PLAYER_TURN_START;
        newState.tossedThisTurn = false; newState.lastDiscardedId = null;
      }
      setGameState(newState);
    }, 1500); 
    return () => clearTimeout(timeout);
  }, [gameState.phase, gameState.currentPlayerIndex, isBotThinking, gameState.players, gameState.deck, gameState.openDeck]); 

  // --- Actions ---
  const handleCardClick = (card: CardData) => {
    if (!isPlayerTurn) return;
    if (gameState.phase === GamePhase.PLAYER_TURN_START) {
      setSelectedCardIds(prev => {
        if (prev.includes(card.id)) return prev.filter(id => id !== card.id);
        if (prev.length >= 2) return [prev[1], card.id]; 
        return [...prev, card.id];
      });
    }
  };

  const handleToss = () => {
    if (selectedCardIds.length !== 2) return;
    if (gameState.tossedThisTurn) return;
    const p = currentPlayer;
    const cards = p.hand.filter(c => selectedCardIds.includes(c.id));
    if (cards[0].rank !== cards[1].rank) { alert("Must toss a pair of the same rank!"); return; }
    const newHand = p.hand.filter(c => !selectedCardIds.includes(c.id));
    const newState = {
      ...gameState,
      players: gameState.players.map(pl => pl.id === p.id ? { ...pl, hand: newHand } : pl),
      pendingToss: cards, phase: GamePhase.PLAYER_TOSSING_DRAW, tossedThisTurn: true
    };
    setGameState(newState); syncOnlineState(newState); setSelectedCardIds([]);
  };

  const handleDiscard = () => {
    if (selectedCardIds.length !== 1) return;
    const p = currentPlayer;
    const cardToDiscard = p.hand.find(c => c.id === selectedCardIds[0]);
    if (!cardToDiscard) return;
    const newHand = p.hand.filter(c => c.id !== selectedCardIds[0]);
    const newState = {
      ...gameState,
      players: gameState.players.map(pl => pl.id === p.id ? { ...pl, hand: newHand } : pl),
      pendingDiscard: cardToDiscard, lastDiscardedId: cardToDiscard.id, phase: GamePhase.PLAYER_DRAW
    };
    setGameState(newState); syncOnlineState(newState); setSelectedCardIds([]);
  };

  const handleDraw = (source: 'DECK' | 'OPEN') => {
    const p = currentPlayer;
    let drawnCard: CardData;
    let newOpenDeck = [...gameState.openDeck];
    let newDeck = [...gameState.deck];
    if (source === 'OPEN') {
      const topCard = newOpenDeck[newOpenDeck.length - 1];
      if (gameState.phase === GamePhase.PLAYER_DRAW && topCard && topCard.id === gameState.lastDiscardedId) {
        if (!p.isBot) alert("Cannot pick up the card you just discarded!");
        return;
      }
      drawnCard = newOpenDeck.pop()!;
    } else {
      if (newDeck.length === 0) {
         if (newOpenDeck.length > 1) {
            const topCard = newOpenDeck.pop()!; 
            const cardsToRecycle = [...newOpenDeck]; 
            newDeck = shuffleDeck(cardsToRecycle); 
            newOpenDeck = [topCard]; 
         } else { handleShow(); return; }
      }
      drawnCard = newDeck.shift()!;
    }
    const newHand = [...p.hand, drawnCard];
    if (gameState.pendingToss.length > 0) newOpenDeck.push(...gameState.pendingToss);
    if (gameState.pendingDiscard) newOpenDeck.push(gameState.pendingDiscard);
    finishTurn(p.id, newHand, newOpenDeck, newDeck);
  };

  const handleShow = () => {
    const results = getRoundScores(gameState.players, gameState.currentPlayerIndex, gameState.roundJoker);
    const updatedPlayers = gameState.players.map(p => {
      const roundRes = results.find(r => r.playerId === p.id);
      return {
        ...p, score: roundRes ? roundRes.roundScore : 0, totalScore: (p.totalScore || 0) + (roundRes ? roundRes.roundScore : 0), wasCaller: p.id === currentPlayer.id 
      };
    });
    const newState = {
      ...gameState, players: updatedPlayers, phase: GamePhase.ROUND_END
    };
    setGameState(newState); syncOnlineState(newState); setIsTransitioning(false);
  };

  const finishTurn = (playerId: number, newHand: CardData[], openDeck: CardData[], deck: CardData[]) => {
    const nextPlayerIndex = (gameState.currentPlayerIndex + 1) % gameState.players.length;
    const needsTransition = gameState.gameMode === 'MULTIPLAYER';
    const newState = {
      ...gameState,
      players: gameState.players.map(pl => pl.id === playerId ? { ...pl, hand: newHand, lastAction: 'Ended Turn' } : pl),
      openDeck, deck, currentPlayerIndex: nextPlayerIndex, phase: GamePhase.PLAYER_TURN_START, lastDiscardedId: null, tossedThisTurn: false, pendingDiscard: null, pendingToss: []
    };
    setGameState(newState); syncOnlineState(newState);
    if (needsTransition) { setIsTransitioning(true); }
  };

  const nextRound = () => {
    if (gameState.roundNumber >= gameState.totalRounds) return;
    startRound(gameState.roundNumber + 1, gameState.players, gameState.gameMode);
  };

  // --- UI COMPONENTS ---

  const TutorialOverlay = () => {
    if (tutorialStep === 0) return null;

    let message = "";
    switch(tutorialStep) {
      case 1: message = "Welcome! Your goal is to get your hand total as close to 0 as possible."; break;
      case 2: message = "Tap a card in your hand to select it for discarding."; break;
      case 3: message = "Now tap the DISCARD button to remove it."; break;
      case 4: message = "Every discard needs a draw. Tap the DECK to pick up a new card."; break;
      case 5: message = "When your total is 5 or less, tap SHOW to end the round. Good luck!"; break;
    }

    return (
      <div className="fixed inset-0 z-[100] flex flex-col items-center justify-center pointer-events-none">
        <div className="absolute inset-0 bg-black/70 backdrop-blur-[2px] pointer-events-auto" />

        <div className="relative z-[110] bg-slate-900 border-2 border-yellow-500 p-6 rounded-2xl shadow-2xl max-w-xs text-center animate-in zoom-in fade-in pointer-events-auto">
          <div className="flex justify-between items-start mb-4">
            <div className="bg-yellow-500 text-black px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-widest">Tutorial {tutorialStep}/5</div>
            <button onClick={skipTutorial} className="text-gray-500 hover:text-white"><X size={18} /></button>
          </div>
          <p className="text-white font-bold mb-6 text-lg leading-tight">{message}</p>
          <div className="flex flex-col gap-2">
            {(tutorialStep === 1 || tutorialStep === 5) && (
              <button onClick={advanceTutorial} className="bg-yellow-500 hover:bg-yellow-400 text-black font-bold py-3 rounded-xl transition-all flex items-center justify-center gap-2">
                {tutorialStep === 5 ? "Start Playing!" : "Next Step"} <ChevronRight size={18} />
              </button>
            )}
            <button onClick={skipTutorial} className="text-gray-400 text-xs hover:text-white py-2">Skip Tutorial</button>
          </div>
        </div>

        <style>{`
          .hand-area, .controls-area, .deck-area { transition: all 0.3s ease; }
          ${tutorialStep === 2 ? '.hand-area { z-index: 110 !important; position: relative; pointer-events: auto !important; box-shadow: 0 0 50px rgba(234, 179, 8, 0.6); }' : ''}
          ${tutorialStep === 3 ? '.controls-area { z-index: 110 !important; position: relative; pointer-events: auto !important; box-shadow: 0 0 50px rgba(234, 179, 8, 0.6); }' : ''}
          ${tutorialStep === 4 ? '.deck-area { z-index: 110 !important; position: relative; pointer-events: auto !important; box-shadow: 0 0 50px rgba(234, 179, 8, 0.6); }' : ''}
          ${tutorialStep > 1 && tutorialStep < 5 ? '.pointer-events-auto { pointer-events: none !important; }' : ''}
        `}</style>
      </div>
    );
  };

  if (authLoading || isReconnecting) return <div className="h-[100dvh] bg-[#1a2e1a] flex flex-col items-center justify-center text-white gap-4"><RefreshCw className="animate-spin text-yellow-500" size={48} /><h2 className="font-serif text-2xl">{isReconnecting ? 'Reconnecting...' : 'Loading...'}</h2></div>;
  if (!session && !isGuest) return <Auth onGuestPlay={() => setIsGuest(true)} />;

  if (isOnlineLobby) {
     return (
        <div className="h-[100dvh] bg-[#1a2e1a] flex flex-col items-center justify-center p-4">
           <div className="bg-slate-900/90 p-8 rounded-2xl border border-yellow-500/30 w-full max-w-md text-center">
              <h1 className="text-3xl font-serif font-bold text-yellow-500 mb-2">Lobby</h1>
              <div className="bg-black/40 p-4 rounded-xl mb-6 flex items-center justify-between border border-white/10">
                 <div className="text-left">
                    <p className="text-xs text-gray-400 uppercase">Room Code</p>
                    <p className="text-3xl font-mono font-bold text-white tracking-widest">{roomCode}</p>
                 </div>
                 <button onClick={() => navigator.clipboard.writeText(roomCode)} className="bg-slate-700 p-2 rounded hover:bg-slate-600">
                    <Copy size={20} className="text-gray-300" />
                 </button>
              </div>
              <div className="mb-8">
                 <h3 className="text-sm font-bold text-gray-400 mb-2 flex items-center justify-center gap-2"><Users size={16}/> Players ({onlineLobbyPlayers.length}/10)</h3>
                 <div className="flex flex-col gap-2">
                    {onlineLobbyPlayers.map(p => (
                       <div key={p.id} className="bg-slate-800 p-3 rounded-lg flex items-center justify-between">
                          <span className="font-bold text-white">{p.name}</span>
                          {p.id === 0 && <span className="text-xs bg-yellow-500 text-black px-2 py-1 rounded font-bold">HOST</span>}
                       </div>
                    ))}
                 </div>
              </div>
              <div className="flex flex-col gap-3">
                 {myOnlineId === 0 ? (
                    <button onClick={startOnlineGame} disabled={onlineLobbyPlayers.length < 2} className="w-full bg-green-600 hover:bg-green-500 text-white font-bold py-4 rounded-xl flex items-center justify-center gap-2">Start Game <Play size={20} /></button>
                 ) : (
                    <div className="w-full bg-slate-700 text-gray-400 font-bold py-4 rounded-xl flex items-center justify-center gap-2 animate-pulse">Waiting for Host...</div>
                 )}
                 <button onClick={clearSession} className="text-red-400 text-sm hover:underline mt-2">Leave Room</button>
              </div>
           </div>
        </div>
     );
  }

  if (!gameState.gameMode && !isNameEntryStep && !showRoundSelectionSP && !showOnlineSelection) {
    return (
      <div className="h-[100dvh] bg-[#1a2e1a] flex flex-col items-center justify-center p-4">
        <h1 className="font-serif text-5xl md:text-7xl font-bold text-yellow-500 mb-8 drop-shadow-2xl">TRI-STACK</h1>
        <div className="absolute top-4 right-4 flex items-center gap-2 text-sm bg-black/30 p-2 rounded-lg backdrop-blur z-50">
          <User size={16} className="text-green-400" />
          <span className="text-gray-300 font-bold">{getDisplayName()}</span>
          {!isGuest && <button onClick={handleSignOut} className="ml-2 text-red-400 hover:text-red-300 border-l border-white/10 pl-2"><LogOut size={16} /></button>}
        </div>
        <div className="bg-slate-900/50 p-8 rounded-2xl backdrop-blur-sm border border-white/10 shadow-2xl flex flex-col gap-6 w-full max-w-md">
           <button onClick={openSinglePlayerSetup} className="bg-blue-600 hover:bg-blue-500 text-white p-6 rounded-xl font-bold text-lg flex items-center gap-4 transition-all">
             <div className="w-12 h-12 bg-blue-800 rounded-full flex items-center justify-center"><User size={24} /></div>
             <div className="text-left"><div>Single Player</div><div className="text-sm text-blue-200 font-normal">VS Bots</div></div>
           </button>
           <button onClick={() => setShowMultiplayerSelection(true)} className="bg-green-600 hover:bg-green-500 text-white p-6 rounded-xl font-bold text-lg flex items-center gap-4 transition-all">
             <div className="w-12 h-12 bg-green-800 rounded-full flex items-center justify-center"><Users size={24} /></div>
             <div className="text-left"><div>Local Play</div><div className="text-sm text-green-200 font-normal">Pass & Play</div></div>
           </button>
           <button onClick={() => setShowOnlineSelection(true)} className="bg-purple-600 hover:bg-purple-500 text-white p-6 rounded-xl font-bold text-lg flex items-center gap-4 transition-all">
             <div className="w-12 h-12 bg-purple-800 rounded-full flex items-center justify-center"><Globe size={24} /></div>
             <div className="text-left"><div>Online Play</div><div className="text-sm text-purple-200 font-normal">Remote Friends</div></div>
           </button>
        </div>
      </div>
    );
  }

  // Simplified UI for Main Game Loop
  if (gameState.phase === GamePhase.SETUP || !currentPlayer) return null;

  if (isTransitioning) {
    return (
      <div className="h-[100dvh] bg-slate-900 flex flex-col items-center justify-center p-4 z-50">
        <div className="max-w-md w-full bg-slate-800 p-8 rounded-2xl shadow-2xl border border-yellow-500/30 text-center animate-in fade-in">
           <div className="w-20 h-20 bg-blue-600 rounded-full flex items-center justify-center mx-auto mb-6"><EyeOff size={40} className="text-white" /></div>
           <p className="text-gray-500 mb-2">Please pass the device to</p>
           <h1 className="text-4xl font-bold text-white mb-8 tracking-tight">{currentPlayer.name}</h1>
           <button onClick={() => setIsTransitioning(false)} className="w-full bg-green-600 hover:bg-green-500 text-white font-bold py-4 rounded-xl flex items-center justify-center gap-3 transition-all transform hover:scale-[1.02]"><Eye size={24} /> I am {currentPlayer.name}</button>
        </div>
      </div>
    );
  }

  return (
    <div className="h-[100dvh] flex flex-col overflow-hidden bg-[#1a2e1a]">
      <TutorialOverlay />

      {/* Top Bar */}
      <div className="h-16 bg-[#0f1f0f] flex items-center justify-between px-4 shadow-lg z-20 shrink-0">
        <div className="flex items-center gap-4">
          <button onClick={() => clearSession()} className="text-red-400 bg-white/5 p-2 rounded-lg"><LogOut size={20} /></button>
          <div className="bg-slate-800 px-3 py-1 rounded-lg text-xs font-bold text-white">R {gameState.roundNumber}/{gameState.totalRounds}</div>
          <div className="flex items-center gap-2"><Sparkles size={14} className="text-purple-400" /><span className="text-xs font-bold text-purple-300">{gameState.roundJoker?.rank} JOKER</span></div>
        </div>
        <div className="flex items-center gap-2">
          <div className={`w-2 h-2 rounded-full ${isBotThinking ? 'bg-yellow-500 animate-pulse' : 'bg-green-500'}`} />
          <span className="text-sm font-bold truncate max-w-[100px] text-white">{currentPlayer.name}</span>
        </div>
      </div>

      <div className="flex-1 relative flex flex-col justify-between p-2 max-w-7xl mx-auto w-full overflow-hidden">
        {/* Opponents Area */}
        <div className="flex justify-center gap-4 mb-2">
           {opponentsToRender.map(opp => (
             <div key={opp.id} className={`flex flex-col items-center p-2 rounded-lg bg-black/20 ${opp.id === gameState.currentPlayerIndex ? 'ring-2 ring-yellow-500 bg-yellow-500/10' : ''}`}>
                <div className="w-10 h-10 bg-slate-700 rounded-full flex items-center justify-center border-2 border-slate-500">{opp.isBot ? <Bot size={20} className="text-slate-300" /> : <User size={20} className="text-slate-300" />}</div>
                <span className="text-[10px] font-bold mt-1 max-w-[50px] truncate">{opp.name}</span>
                <span className="text-[10px] text-yellow-400 font-bold">{opp.totalScore || 0} pts</span>
             </div>
           ))}
        </div>

        {/* Center Board (Deck & Discard) */}
        <div className="flex items-center justify-center gap-8 my-4 deck-area">
           {/* Draw Pile */}
           <div className="flex flex-col items-center gap-2">
             <Card 
               onClick={() => (gameState.phase === GamePhase.PLAYER_DRAW || gameState.phase === GamePhase.PLAYER_TOSSING_DRAW) && handleDraw('DECK')} 
               disabled={gameState.phase === GamePhase.PLAYER_TURN_START}
             />
             <span className="text-[10px] font-bold text-gray-400">DECK</span>
           </div>

           {/* Discard Pile */}
           <div className="flex flex-col items-center gap-2">
              {gameState.openDeck.length > 0 ? (
                <Card 
                  card={gameState.openDeck[gameState.openDeck.length - 1]} 
                  onClick={() => (gameState.phase === GamePhase.PLAYER_DRAW || gameState.phase === GamePhase.PLAYER_TOSSING_DRAW) && handleDraw('OPEN')}
                  disabled={gameState.phase === GamePhase.PLAYER_TURN_START}
                />
              ) : (
                <div className="w-20 h-28 md:w-24 md:h-36 border-2 border-dashed border-white/20 rounded-xl flex items-center justify-center">
                   <span className="text-[10px] text-white/20 uppercase font-bold text-center p-2">Discard Pile</span>
                </div>
              )}
              <span className="text-[10px] font-bold text-gray-400">OPEN</span>
           </div>
        </div>

        {/* Player Action Area */}
        <div className="flex flex-col items-center gap-4 mb-4">
           {isPlayerTurn && (
             <div className="bg-yellow-500/10 border border-yellow-500/20 px-6 py-2 rounded-full mb-2 animate-in slide-in-from-bottom duration-300">
               <span className="text-yellow-500 font-bold text-sm tracking-widest uppercase flex items-center gap-2">
                 <div className="w-2 h-2 bg-yellow-500 rounded-full animate-pulse" />
                 It's Your Turn
               </span>
             </div>
           )}

           <div className="flex gap-4 controls-area">
              <button 
                onClick={handleToss}
                disabled={!isPlayerTurn || gameState.phase !== GamePhase.PLAYER_TURN_START || selectedCardIds.length !== 2 || gameState.tossedThisTurn}
                className={`flex flex-col items-center justify-center gap-1 w-20 h-16 rounded-2xl font-bold transition-all border-b-4 ${selectedCardIds.length === 2 ? 'bg-indigo-600 text-white border-indigo-800 scale-105 shadow-lg shadow-indigo-900/30' : 'bg-slate-800 text-slate-500 border-slate-900 opacity-50'}`}
              >
                 <Hand size={18} /> <span className="text-[10px] uppercase">Toss</span>
              </button>
              <button 
                onClick={handleDiscard}
                disabled={!isPlayerTurn || gameState.phase !== GamePhase.PLAYER_TURN_START || selectedCardIds.length !== 1}
                className={`flex flex-col items-center justify-center gap-1 w-20 h-16 rounded-2xl font-bold transition-all border-b-4 ${selectedCardIds.length === 1 ? 'bg-slate-700 text-white border-slate-900 scale-105 shadow-lg shadow-slate-900/40' : 'bg-slate-800 text-slate-500 border-slate-900 opacity-50'}`}
              >
                 <RefreshCw size={18} /> <span className="text-[10px] uppercase">Discard</span>
              </button>
              <button 
                onClick={handleShow}
                disabled={!isPlayerTurn || gameState.phase !== GamePhase.PLAYER_TURN_START || calculateHandValue(bottomPlayer.hand, gameState.roundJoker) > 5}
                className={`flex flex-col items-center justify-center gap-1 w-20 h-16 rounded-2xl font-bold transition-all border-b-4 ${isPlayerTurn && gameState.phase === GamePhase.PLAYER_TURN_START && calculateHandValue(bottomPlayer.hand, gameState.roundJoker) <= 5 ? 'bg-yellow-500 text-black border-yellow-700 scale-110 shadow-lg shadow-yellow-900/40' : 'bg-slate-800 text-slate-500 border-slate-900 opacity-50'}`}
              >
                 <Eye size={18} /> <span className="text-[10px] uppercase">Show</span>
              </button>
           </div>
        </div>

        {/* Player Hand */}
        <div className="flex flex-col items-center hand-area">
           <div className="flex justify-center gap-1 md:gap-4 h-44 items-end">
              {bottomPlayer.hand.map(card => (
                <Card 
                  key={card.id} 
                  card={card} 
                  selected={selectedCardIds.includes(card.id)} 
                  onClick={() => handleCardClick(card)}
                  isJoker={card.rank === gameState.roundJoker?.rank}
                  disabled={!isPlayerTurn || (gameState.phase !== GamePhase.PLAYER_TURN_START)}
                />
              ))}
           </div>
           <div className="mt-2 bg-black/40 px-4 py-1 rounded-full text-xs font-bold text-gray-300 border border-white/5">
              Hand Total: <span className="text-yellow-500">{calculateHandValue(bottomPlayer.hand, gameState.roundJoker)}</span>
           </div>
        </div>
      </div>

      {/* Round End Overlay */}
      {gameState.phase === GamePhase.ROUND_END && (
        <div className="fixed inset-0 z-50 bg-black/90 flex flex-col items-center justify-center p-4 animate-in fade-in duration-500">
           <Trophy className="text-yellow-500 mb-4 animate-bounce" size={64} />
           <h2 className="text-3xl font-serif font-bold text-white mb-8">Round {gameState.roundNumber} Results</h2>
           <div className="w-full max-w-md flex flex-col gap-3 mb-8">
              {gameState.players.sort((a,b) => a.score - b.score).map(p => (
                <div key={p.id} className={`flex items-center justify-between p-4 rounded-xl border ${p.wasCaller ? 'bg-yellow-500/10 border-yellow-500' : 'bg-white/5 border-white/10'}`}>
                   <div className="flex flex-col">
                      <span className="font-bold text-white flex items-center gap-2">{p.name} {p.wasCaller && <span className="text-[10px] bg-yellow-500 text-black px-1 rounded">CALLER</span>}</span>
                      <div className="flex gap-1 mt-1">
                         {p.hand.map(c => (
                           <Card key={c.id} card={c} small isJoker={c.rank === gameState.roundJoker?.rank} />
                         ))}
                      </div>
                   </div>
                   <div className="text-right">
                      <div className="text-2xl font-bold text-yellow-500">+{p.score}</div>
                      <div className="text-xs text-gray-500">Total: {p.totalScore}</div>
                   </div>
                </div>
              ))}
           </div>
           {gameState.roundNumber < gameState.totalRounds ? (
             <button onClick={nextRound} className="w-full max-w-xs bg-green-600 hover:bg-green-500 text-white font-bold py-4 rounded-xl flex items-center justify-center gap-2">Next Round <ChevronRight /></button>
           ) : (
             <div className="text-center">
                <h2 className="text-2xl text-yellow-500 font-serif mb-4">MATCH OVER!</h2>
                <button onClick={clearSession} className="bg-slate-700 hover:bg-slate-600 text-white font-bold py-4 px-8 rounded-xl">Back to Menu</button>
             </div>
           )}
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { GameState, Player, CardData, GamePhase, GameMode } from './types';
import { createDeck, getRoundScores, calculateHandValue, decideBotAction, shuffleDeck } from './services/gameLogic';
import { createRoom, joinRoom, subscribeToRoom, updateGameState, getRoomData } from './services/online';
import { DEFAULT_TOTAL_ROUNDS } from './constants';
import Card from './components/Card';
import Auth from './components/Auth';
import { supabase, signOut } from './services/supabase';
import { 
  RefreshCw, Trophy, Users, Hand, ChevronRight, EyeOff, Eye, 
  User, Bot, Play, Sparkles, LogOut, Globe, Copy, X 
} from 'lucide-react';

const SESSION_KEY = 'TRI_STACK_SESSION';
const NAME_KEY = 'TRI_STACK_PLAYER_NAME';
const TUTORIAL_KEY = 'TRI_STACK_TUTORIAL_COMPLETE_V5';

// --- Sub-components (outside for stability) ---

interface TutorialOverlayProps {
  step: number;
  onSkip: () => void;
  onNext: () => void;
}

const TutorialOverlay: React.FC<TutorialOverlayProps> = ({ step, onSkip, onNext }) => {
  if (step === 0) return null;

  let message = "";
  switch(step) {
    case 1: message = "Welcome! Your goal is to get your hand total as close to 0 as possible."; break;
    case 2: message = "Tap a card in your hand to select it for discarding."; break;
    case 3: message = "Now tap the DISCARD button to remove it."; break;
    case 4: message = "Every discard needs a draw. Tap the DECK to pick up a new card."; break;
    case 5: message = "When your total is 5 or less, tap SHOW to end the round. Good luck!"; break;
  }

  return (
    <div className="fixed inset-0 z-[100] flex flex-col items-center justify-center pointer-events-none">
      <div className="absolute inset-0 bg-black/80 backdrop-blur-[2px] pointer-events-auto" />

      <div className="relative z-[110] bg-slate-900 border-2 border-yellow-500 p-6 rounded-2xl shadow-2xl max-w-xs text-center animate-in zoom-in fade-in pointer-events-auto">
        <div className="flex justify-between items-start mb-4">
          <div className="bg-yellow-500 text-black px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-widest">Guide {step}/5</div>
          <button onClick={onSkip} className="text-gray-500 hover:text-white"><X size={18} /></button>
        </div>
        <p className="text-white font-bold mb-6 text-lg leading-tight">{message}</p>
        <div className="flex flex-col gap-2">
          {(step === 1 || step === 5) && (
            <button onClick={onNext} className="bg-yellow-500 hover:bg-yellow-400 text-black font-bold py-3 rounded-xl transition-all flex items-center justify-center gap-2">
              {step === 5 ? "Start Playing!" : "Next Step"} <ChevronRight size={18} />
            </button>
          )}
          <button onClick={onSkip} className="text-gray-400 text-xs hover:text-white py-2">Skip Tutorial</button>
        </div>
      </div>

      <style>{`
        ${step === 2 ? '.hand-area { z-index: 110 !important; position: relative; box-shadow: 0 0 50px rgba(234, 179, 8, 0.4); border-radius: 20px; }' : ''}
        ${step === 3 ? '.controls-area { z-index: 110 !important; position: relative; box-shadow: 0 0 50px rgba(234, 179, 8, 0.4); border-radius: 20px; }' : ''}
        ${step === 4 ? '.deck-area { z-index: 110 !important; position: relative; box-shadow: 0 0 50px rgba(234, 179, 8, 0.4); border-radius: 20px; }' : ''}
      `}</style>
    </div>
  );
};

// --- Main App Component ---

const App: React.FC = () => {
  // --- Auth State ---
  const [session, setSession] = useState<any>(null);
  const [isGuest, setIsGuest] = useState(false);
  const [authLoading, setAuthLoading] = useState(true);

  // --- Tutorial State ---
  const [hasSeenTutorial, setHasSeenTutorial] = useState<boolean>(() => {
    try { return localStorage.getItem(TUTORIAL_KEY) === 'true'; } catch { return false; }
  });
  const [tutorialStep, setTutorialStep] = useState(0);

  // --- Game State ---
  const [gameState, setGameState] = useState<GameState>({
    gameMode: null, deck: [], openDeck: [], players: [], currentPlayerIndex: 0,
    roundJoker: null, roundNumber: 1, totalRounds: DEFAULT_TOTAL_ROUNDS,
    phase: GamePhase.SETUP, turnLog: [], winner: null, lastDiscardedId: null,
    tossedThisTurn: false, pendingDiscard: null, pendingToss: [], playerNames: []
  });

  const [selectedCardIds, setSelectedCardIds] = useState<string[]>([]);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [showOnlineSelection, setShowOnlineSelection] = useState(false); 
  const [showRoundSelectionSP, setShowRoundSelectionSP] = useState(false);
  const [selectedTotalRounds, setSelectedTotalRounds] = useState(DEFAULT_TOTAL_ROUNDS);
  const [customDisplayName, setCustomDisplayName] = useState('');

  // Online Specific State
  const [roomCode, setRoomCode] = useState('');
  const [joinCodeInput, setJoinCodeInput] = useState('');
  const [myOnlineId, setMyOnlineId] = useState<number | null>(null); 
  const [onlineLobbyPlayers, setOnlineLobbyPlayers] = useState<{id: number, name: string}[]>([]);
  const [isOnlineLobby, setIsOnlineLobby] = useState(false);
  const [isReconnecting, setIsReconnecting] = useState(false); 
  const [isJoining, setIsJoining] = useState(false); 

  // --- Auth Effect ---
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setAuthLoading(false);
    }).catch(() => setAuthLoading(false));

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });
    return () => subscription.unsubscribe();
  }, []);

  // --- Load Custom Name ---
  useEffect(() => {
    try {
      const savedName = localStorage.getItem(NAME_KEY);
      if (savedName) setCustomDisplayName(savedName);
    } catch (e) {}
  }, []);

  const getDisplayName = () => {
    if (customDisplayName) return customDisplayName;
    return isGuest ? 'Guest' : (session?.user?.email?.split('@')[0] || 'Player');
  };

  // --- Tutorial Steps ---
  const skipTutorial = () => {
    setTutorialStep(0);
    setHasSeenTutorial(true);
    try { localStorage.setItem(TUTORIAL_KEY, 'true'); } catch {}
  };

  const advanceTutorial = () => {
    if (tutorialStep === 5) skipTutorial();
    else setTutorialStep(prev => prev + 1);
  };

  // Auto-advance tutorial logic
  useEffect(() => {
    if (tutorialStep === 2 && selectedCardIds.length > 0) setTutorialStep(3);
    if (tutorialStep === 3 && gameState.phase === GamePhase.PLAYER_DRAW) setTutorialStep(4);
    if (tutorialStep === 4 && gameState.phase === GamePhase.PLAYER_TURN_START && gameState.currentPlayerIndex !== 0) {
      setTutorialStep(5);
    }
  }, [tutorialStep, selectedCardIds, gameState.phase, gameState.currentPlayerIndex]);

  // --- Reconnection Logic ---
  useEffect(() => {
    const checkSession = async () => {
      try {
        const savedSession = localStorage.getItem(SESSION_KEY);
        if (savedSession) {
          setIsReconnecting(true);
          const { code, playerId } = JSON.parse(savedSession);
          const { data: roomData, error } = await getRoomData(code);
          if (error || !roomData) {
             localStorage.removeItem(SESSION_KEY);
             setIsReconnecting(false);
             return;
          }
          setRoomCode(code);
          setMyOnlineId(playerId);
          setIsGuest(true);
          if (roomData.status === 'WAITING') {
            setOnlineLobbyPlayers(roomData.players || []);
            setIsOnlineLobby(true);
          } else if (roomData.game_state) {
            setGameState({ ...roomData.game_state, gameMode: (playerId === 0 ? 'ONLINE_HOST' : 'ONLINE_CLIENT') });
          }
        }
      } catch (e) {
        localStorage.removeItem(SESSION_KEY);
      } finally {
        setIsReconnecting(false);
      }
    };
    checkSession();
  }, []);

  // --- Online Subscription ---
  useEffect(() => {
    if (!roomCode) return;
    const subscription = subscribeToRoom(roomCode, (roomData) => {
      if (roomData.status === 'WAITING') {
         setOnlineLobbyPlayers(roomData.players || []);
      } else if (roomData.game_state) {
         setGameState({ ...roomData.game_state, gameMode: (myOnlineId === 0 ? 'ONLINE_HOST' : 'ONLINE_CLIENT') });
         setIsOnlineLobby(false);
         setShowOnlineSelection(false);
      }
    });
    return () => { supabase.removeChannel(subscription); };
  }, [roomCode, myOnlineId]);

  const clearSession = () => {
    localStorage.removeItem(SESSION_KEY);
    setRoomCode('');
    setMyOnlineId(null);
    setIsOnlineLobby(false);
    setGameState({
      gameMode: null, deck: [], openDeck: [], players: [], currentPlayerIndex: 0,
      roundJoker: null, roundNumber: 1, totalRounds: DEFAULT_TOTAL_ROUNDS,
      phase: GamePhase.SETUP, turnLog: [], winner: null, lastDiscardedId: null,
      tossedThisTurn: false, pendingDiscard: null, pendingToss: [], playerNames: []
    });
    setSelectedCardIds([]);
    setIsTransitioning(false);
  };

  const currentPlayer = gameState.players[gameState.currentPlayerIndex] || null;
  const bottomPlayer = (gameState.gameMode === 'SINGLE_PLAYER' || (gameState.gameMode?.startsWith('ONLINE') && myOnlineId !== null))
    ? (gameState.players.find(p => p.id === (myOnlineId ?? 0)) || currentPlayer)
    : currentPlayer;

  const opponents = gameState.players.filter(p => p.id !== (bottomPlayer?.id ?? -1));
  const isMyTurn = (gameState.gameMode?.startsWith('ONLINE')) ? (currentPlayer?.id === myOnlineId) : true;
  const isPlayerTurn = !isTransitioning && currentPlayer && !currentPlayer.isBot && gameState.phase !== GamePhase.ROUND_END && isMyTurn;
  const isBotThinking = gameState.gameMode === 'SINGLE_PLAYER' && currentPlayer?.isBot && !isTransitioning && gameState.phase !== GamePhase.ROUND_END;

  // --- Actions ---
  const handleCreateOnline = async () => {
    const { code, error } = await createRoom(getDisplayName(), session?.user?.id || 'guest');
    if (error) return alert("Error creating room");
    setRoomCode(code);
    setMyOnlineId(0);
    localStorage.setItem(SESSION_KEY, JSON.stringify({ code, playerId: 0 }));
    setOnlineLobbyPlayers([{ id: 0, name: getDisplayName() }]);
    setIsOnlineLobby(true);
  };

  const handleJoinOnline = async () => {
    if (joinCodeInput.length !== 4) return;
    setIsJoining(true);
    const { success, error, playerId, players } = await joinRoom(joinCodeInput.toUpperCase(), getDisplayName());
    if (!success) {
      alert(error);
      setIsJoining(false);
      return;
    }
    setRoomCode(joinCodeInput.toUpperCase());
    setMyOnlineId(playerId!);
    localStorage.setItem(SESSION_KEY, JSON.stringify({ code: joinCodeInput.toUpperCase(), playerId }));
    setOnlineLobbyPlayers(players!);
    setIsOnlineLobby(true);
    setIsJoining(false);
  };

  const startSinglePlayer = (rounds: number) => {
    setSelectedTotalRounds(rounds);
    setGameState(prev => ({ ...prev, gameMode: 'SINGLE_PLAYER', phase: GamePhase.SETUP }));
    setShowRoundSelectionSP(false);
    if (!hasSeenTutorial) setTutorialStep(1);
  };

  const startRound = useCallback((roundNum: number, existingPlayers?: Player[], mode?: GameMode) => {
    const newDeck = createDeck();
    const roundJoker = { ...newDeck[Math.floor(Math.random() * newDeck.length)] };
    let players: Player[] = [];

    if (existingPlayers) {
      players = existingPlayers.map(p => ({ 
        ...p, hand: [], score: 0, lastAction: 'Waiting...', wasCaller: false 
      }));
    } else {
      const names = [getDisplayName(), 'Bot Alpha', 'Bot Beta', 'Bot Gamma'];
      players = names.map((n, i) => ({
        id: i, name: n, isBot: i > 0, hand: [], score: 0, totalScore: 0, lastAction: 'Waiting...'
      }));
    }

    players.forEach(p => { p.hand = newDeck.splice(0, 3); });
    const newState: GameState = {
      ...gameState, deck: newDeck, openDeck: [], players, currentPlayerIndex: 0,
      roundJoker, roundNumber: roundNum, totalRounds: selectedTotalRounds,
      phase: GamePhase.PLAYER_TURN_START, tossedThisTurn: false, gameMode: (mode || gameState.gameMode)
    };
    setGameState(newState);
    if (mode === 'ONLINE_HOST' || gameState.gameMode === 'ONLINE_HOST') updateGameState(roomCode, newState);
    setSelectedCardIds([]);
  }, [getDisplayName, gameState, selectedTotalRounds, roomCode]);

  useEffect(() => {
    if (gameState.phase === GamePhase.SETUP && gameState.gameMode && !gameState.gameMode.startsWith('ONLINE')) {
      startRound(1, undefined, gameState.gameMode);
    }
  }, [gameState.phase, gameState.gameMode, startRound]);

  // --- Bot Effect ---
  useEffect(() => {
    if (!isBotThinking || !currentPlayer) return;
    const timeout = setTimeout(() => {
      let newState = { ...gameState };
      if (gameState.phase === GamePhase.PLAYER_TURN_START) {
        const action = decideBotAction(currentPlayer, gameState.roundJoker, gameState.tossedThisTurn);
        if (action.type === 'SHOW') {
           const results = getRoundScores(gameState.players, gameState.currentPlayerIndex, gameState.roundJoker);
           newState.players = gameState.players.map(pl => {
             const res = results.find(r => r.playerId === pl.id);
             return { ...pl, score: res?.roundScore || 0, totalScore: pl.totalScore + (res?.roundScore || 0), wasCaller: pl.id === currentPlayer.id };
           });
           newState.phase = GamePhase.ROUND_END;
        } else if (action.type === 'TOSS') {
           const cards = currentPlayer.hand.filter(c => action.cardIds?.includes(c.id));
           newState.players = newState.players.map(pl => pl.id === currentPlayer.id ? { ...pl, hand: pl.hand.filter(c => !action.cardIds?.includes(c.id)) } : pl);
           newState.pendingToss = cards; newState.phase = GamePhase.PLAYER_TOSSING_DRAW; newState.tossedThisTurn = true;
        } else {
           const card = currentPlayer.hand.find(c => c.id === action.cardIds![0])!;
           newState.players = newState.players.map(pl => pl.id === currentPlayer.id ? { ...pl, hand: pl.hand.filter(c => c.id !== card.id) } : pl);
           newState.pendingDiscard = card; newState.lastDiscardedId = card.id; newState.phase = GamePhase.PLAYER_DRAW;
        }
      } else {
        const drawn = newState.deck.shift()!;
        newState.players = newState.players.map(pl => pl.id === currentPlayer.id ? { ...pl, hand: [...pl.hand, drawn] } : pl);
        if (newState.pendingToss.length) newState.openDeck = [...newState.openDeck, ...newState.pendingToss];
        if (newState.pendingDiscard) newState.openDeck = [...newState.openDeck, newState.pendingDiscard];
        newState.pendingToss = []; newState.pendingDiscard = null;
        newState.currentPlayerIndex = (newState.currentPlayerIndex + 1) % newState.players.length;
        newState.phase = GamePhase.PLAYER_TURN_START; newState.tossedThisTurn = false;
      }
      setGameState(newState);
    }, 1000);
    return () => clearTimeout(timeout);
  }, [isBotThinking, gameState, currentPlayer]);

  // --- Handlers ---
  const handleCardClick = (card: CardData) => {
    if (!isPlayerTurn) return;
    setSelectedCardIds(prev => prev.includes(card.id) ? prev.filter(id => id !== card.id) : (prev.length >= 2 ? [prev[1], card.id] : [...prev, card.id]));
  };

  const handleDiscard = () => {
    if (selectedCardIds.length !== 1 || !bottomPlayer) return;
    const card = bottomPlayer.hand.find(c => c.id === selectedCardIds[0])!;
    const newState = {
      ...gameState, 
      players: gameState.players.map(pl => pl.id === bottomPlayer.id ? { ...pl, hand: pl.hand.filter(c => c.id !== card.id) } : pl),
      pendingDiscard: card, lastDiscardedId: card.id, phase: GamePhase.PLAYER_DRAW
    };
    setGameState(newState); if (roomCode) updateGameState(roomCode, newState); setSelectedCardIds([]);
  };

  const handleDraw = (source: 'DECK' | 'OPEN') => {
    if (!bottomPlayer) return;
    let drawn: CardData;
    let newDeck = [...gameState.deck];
    let newOpen = [...gameState.openDeck];
    if (source === 'OPEN') drawn = newOpen.pop()!;
    else {
      if (newDeck.length === 0) {
        const top = newOpen.pop()!;
        newDeck = shuffleDeck(newOpen);
        newOpen = [top];
      }
      drawn = newDeck.shift()!;
    }
    const nextIdx = (gameState.currentPlayerIndex + 1) % gameState.players.length;
    const newState = {
      ...gameState, deck: newDeck, openDeck: [...newOpen, ...(gameState.pendingToss), ...(gameState.pendingDiscard ? [gameState.pendingDiscard] : [])],
      players: gameState.players.map(pl => pl.id === bottomPlayer.id ? { ...pl, hand: [...pl.hand, drawn] } : pl),
      currentPlayerIndex: nextIdx, phase: GamePhase.PLAYER_TURN_START, tossedThisTurn: false, pendingDiscard: null, pendingToss: []
    };
    setGameState(newState); if (roomCode) updateGameState(roomCode, newState);
  };

  const handleShow = () => {
    if (!currentPlayer) return;
    const res = getRoundScores(gameState.players, gameState.currentPlayerIndex, gameState.roundJoker);
    const newState = {
      ...gameState, phase: GamePhase.ROUND_END,
      players: gameState.players.map(pl => {
        const r = res.find(i => i.playerId === pl.id);
        return { ...pl, score: r?.roundScore || 0, totalScore: pl.totalScore + (r?.roundScore || 0), wasCaller: pl.id === currentPlayer.id };
      })
    };
    setGameState(newState); if (roomCode) updateGameState(roomCode, newState);
  };

  if (authLoading || isReconnecting) return <div className="h-screen bg-[#1a2e1a] flex flex-col items-center justify-center text-white gap-4"><RefreshCw className="animate-spin text-yellow-500" size={48} /><h2 className="font-serif text-2xl">Loading Tri-Stack...</h2></div>;
  if (!session && !isGuest) return <Auth onGuestPlay={() => setIsGuest(true)} />;

  // Lobby UI
  if (isOnlineLobby) {
    return (
      <div className="h-screen bg-[#1a2e1a] flex flex-col items-center justify-center p-4">
        <div className="bg-slate-900/90 p-8 rounded-2xl border border-yellow-500/30 w-full max-w-md text-center">
          <h1 className="text-3xl font-serif font-bold text-yellow-500 mb-6 tracking-tight uppercase">Room Lobby</h1>
          <div className="bg-black/40 p-4 rounded-xl mb-6 flex items-center justify-between border border-white/10">
            <div className="text-left">
              <p className="text-[10px] text-gray-400 uppercase font-bold tracking-widest">Code</p>
              <p className="text-3xl font-mono font-bold text-white tracking-widest">{roomCode}</p>
            </div>
            <button onClick={() => navigator.clipboard.writeText(roomCode)} className="bg-slate-700 p-2 rounded hover:bg-slate-600 transition-colors"><Copy size={20} className="text-gray-300" /></button>
          </div>
          <div className="mb-8">
            <h3 className="text-xs font-bold text-gray-500 mb-4 uppercase tracking-widest flex items-center justify-center gap-2">Players Connected</h3>
            <div className="flex flex-col gap-2">
              {onlineLobbyPlayers.map(p => (
                <div key={p.id} className="bg-slate-800 p-3 rounded-lg flex items-center justify-between border border-white/5">
                  <span className="font-bold text-white">{p.name}</span>
                  {p.id === 0 && <span className="text-[9px] bg-yellow-500 text-black px-2 py-0.5 rounded font-black">HOST</span>}
                </div>
              ))}
            </div>
          </div>
          <div className="flex flex-col gap-3">
            {myOnlineId === 0 ? (
              <button onClick={() => startRound(1, undefined, 'ONLINE_HOST')} disabled={onlineLobbyPlayers.length < 2} className="w-full bg-green-600 hover:bg-green-500 text-white font-bold py-4 rounded-xl flex items-center justify-center gap-2 disabled:opacity-50 transition-all">Start Match <Play size={20} /></button>
            ) : (
              <div className="w-full bg-slate-800 text-gray-500 font-bold py-4 rounded-xl flex items-center justify-center gap-2 animate-pulse">Waiting for host...</div>
            )}
            <button onClick={clearSession} className="text-red-400 text-sm font-bold hover:underline mt-2">Leave Room</button>
          </div>
        </div>
      </div>
    );
  }

  // Menu UI
  if (!gameState.gameMode && !showRoundSelectionSP && !showOnlineSelection) {
    return (
      <div className="h-screen bg-[#1a2e1a] flex flex-col items-center justify-center p-4">
        <h1 className="font-serif text-5xl md:text-7xl font-bold text-yellow-500 mb-12 drop-shadow-2xl">TRI-STACK</h1>
        <div className="bg-slate-900/40 p-8 rounded-3xl backdrop-blur-md border border-white/5 shadow-2xl flex flex-col gap-5 w-full max-w-md">
           <button onClick={() => setShowRoundSelectionSP(true)} className="bg-blue-600 hover:bg-blue-500 text-white p-6 rounded-2xl font-bold text-lg flex items-center gap-4 transition-all transform hover:scale-[1.02]">
             <div className="w-12 h-12 bg-blue-800 rounded-full flex items-center justify-center shadow-inner"><User size={24} /></div>
             <div className="text-left"><div>Single Player</div><div className="text-xs text-blue-200 font-normal">Train against Bots</div></div>
           </button>
           <button onClick={() => setShowOnlineSelection(true)} className="bg-purple-600 hover:bg-purple-500 text-white p-6 rounded-2xl font-bold text-lg flex items-center gap-4 transition-all transform hover:scale-[1.02]">
             <div className="w-12 h-12 bg-purple-800 rounded-full flex items-center justify-center shadow-inner"><Globe size={24} /></div>
             <div className="text-left"><div>Online Play</div><div className="text-xs text-purple-200 font-normal">Play with Friends</div></div>
           </button>
        </div>
      </div>
    );
  }

  // Game UI
  if (!gameState.gameMode || !currentPlayer || !bottomPlayer) return null;

  return (
    <div className="h-screen flex flex-col overflow-hidden bg-[#1a2e1a] select-none">
      <TutorialOverlay step={tutorialStep} onSkip={skipTutorial} onNext={advanceTutorial} />

      {/* Header */}
      <div className="h-14 bg-black/40 backdrop-blur flex items-center justify-between px-4 z-20 border-b border-white/5">
        <div className="flex items-center gap-3">
          <button onClick={clearSession} className="text-red-400 bg-white/5 p-2 rounded-lg"><LogOut size={18} /></button>
          <div className="bg-white/10 px-3 py-1 rounded-full text-[10px] font-black text-white tracking-widest">ROUND {gameState.roundNumber}/{gameState.totalRounds}</div>
        </div>
        <div className="flex items-center gap-2">
          <Sparkles size={14} className="text-yellow-500 animate-pulse" />
          <span className="text-xs font-black text-yellow-500 uppercase tracking-tighter">{gameState.roundJoker?.rank} JOKER</span>
        </div>
      </div>

      <div className="flex-1 flex flex-col justify-between p-2 max-w-xl mx-auto w-full relative">
        {/* Opponents */}
        <div className="flex justify-center gap-3 mt-2">
           {opponents.map(opp => (
             <div key={opp.id} className={`flex flex-col items-center p-2 rounded-xl transition-all ${opp.id === gameState.currentPlayerIndex ? 'bg-yellow-500/10 ring-1 ring-yellow-500/50 scale-105' : 'bg-black/20'}`}>
                <div className={`w-8 h-8 rounded-full flex items-center justify-center border ${opp.id === gameState.currentPlayerIndex ? 'bg-yellow-500 text-black border-yellow-400' : 'bg-slate-700 text-slate-400 border-white/5'}`}>{opp.isBot ? <Bot size={16} /> : <User size={16} />}</div>
                <span className="text-[9px] font-bold mt-1 text-white/80 uppercase tracking-tighter max-w-[45px] truncate">{opp.name}</span>
                <span className="text-[10px] text-yellow-500 font-black">{opp.totalScore}</span>
             </div>
           ))}
        </div>

        {/* Board */}
        <div className="flex items-center justify-center gap-10 deck-area py-6">
           <div className="flex flex-col items-center gap-2">
             <Card 
               onClick={() => (gameState.phase === GamePhase.PLAYER_DRAW || gameState.phase === GamePhase.PLAYER_TOSSING_DRAW) && handleDraw('DECK')} 
               disabled={gameState.phase === GamePhase.PLAYER_TURN_START}
             />
             <span className="text-[9px] font-black text-gray-500 tracking-widest uppercase">Deck</span>
           </div>
           <div className="flex flex-col items-center gap-2">
              {gameState.openDeck.length > 0 ? (
                <Card 
                  card={gameState.openDeck[gameState.openDeck.length - 1]} 
                  onClick={() => (gameState.phase === GamePhase.PLAYER_DRAW || gameState.phase === GamePhase.PLAYER_TOSSING_DRAW) && handleDraw('OPEN')}
                  disabled={gameState.phase === GamePhase.PLAYER_TURN_START}
                />
              ) : (
                <div className="w-16 h-24 border border-dashed border-white/10 rounded-xl flex items-center justify-center">
                   <span className="text-[8px] text-white/10 font-black uppercase text-center">Empty</span>
                </div>
              )}
              <span className="text-[9px] font-black text-gray-500 tracking-widest uppercase">Discard</span>
           </div>
        </div>

        {/* Action Area */}
        <div className="flex flex-col items-center gap-4 mb-4">
           {isPlayerTurn && (
             <div className="bg-yellow-500/20 px-6 py-1.5 rounded-full border border-yellow-500/30 animate-pulse">
               <span className="text-yellow-500 font-black text-[10px] uppercase tracking-[0.2em]">Your Turn</span>
             </div>
           )}

           <div className="flex gap-4 controls-area">
              <button 
                onClick={handleDiscard}
                disabled={!isPlayerTurn || gameState.phase !== GamePhase.PLAYER_TURN_START || selectedCardIds.length !== 1}
                className={`w-20 h-16 rounded-2xl flex flex-col items-center justify-center gap-1 font-black transition-all border-b-4 ${selectedCardIds.length === 1 ? 'bg-slate-700 text-white border-slate-900 scale-110 shadow-xl' : 'bg-slate-800 text-slate-600 border-slate-950 opacity-40'}`}
              >
                 <RefreshCw size={18} /> <span className="text-[9px] uppercase tracking-widest">Discard</span>
              </button>
              <button 
                onClick={handleShow}
                disabled={!isPlayerTurn || gameState.phase !== GamePhase.PLAYER_TURN_START || calculateHandValue(bottomPlayer.hand, gameState.roundJoker) > 5}
                className={`w-20 h-16 rounded-2xl flex flex-col items-center justify-center gap-1 font-black transition-all border-b-4 ${isPlayerTurn && gameState.phase === GamePhase.PLAYER_TURN_START && calculateHandValue(bottomPlayer.hand, gameState.roundJoker) <= 5 ? 'bg-yellow-500 text-black border-yellow-700 scale-125 shadow-2xl' : 'bg-slate-800 text-slate-600 border-slate-950 opacity-40'}`}
              >
                 <Eye size={18} /> <span className="text-[9px] uppercase tracking-widest">Show</span>
              </button>
           </div>
        </div>

        {/* Hand */}
        <div className="flex flex-col items-center hand-area pb-4">
           <div className="flex justify-center gap-2 h-40 items-end">
              {bottomPlayer.hand.map(card => (
                <Card 
                  key={card.id} card={card} 
                  selected={selectedCardIds.includes(card.id)} 
                  onClick={() => handleCardClick(card)}
                  isJoker={card.rank === gameState.roundJoker?.rank}
                  disabled={!isPlayerTurn || gameState.phase !== GamePhase.PLAYER_TURN_START}
                />
              ))}
           </div>
           <div className="mt-4 bg-black/40 px-5 py-1.5 rounded-full text-[10px] font-black text-white/60 tracking-widest border border-white/5">
              SCORE: <span className="text-yellow-500">{calculateHandValue(bottomPlayer.hand, gameState.roundJoker)}</span>
           </div>
        </div>
      </div>

      {/* Round End Overlay */}
      {gameState.phase === GamePhase.ROUND_END && (
        <div className="fixed inset-0 z-50 bg-black/95 flex flex-col items-center justify-center p-6 animate-in fade-in zoom-in duration-300">
           <Trophy className="text-yellow-500 mb-6 drop-shadow-[0_0_30px_rgba(234,179,8,0.5)]" size={80} />
           <h2 className="text-3xl font-serif font-bold text-white mb-8 tracking-tight">Round Results</h2>
           <div className="w-full max-w-sm flex flex-col gap-3 mb-10">
              {gameState.players.sort((a,b) => a.score - b.score).map(p => (
                <div key={p.id} className={`flex items-center justify-between p-4 rounded-2xl border ${p.wasCaller ? 'bg-yellow-500/10 border-yellow-500/50' : 'bg-white/5 border-white/5'}`}>
                   <span className="font-bold text-white text-sm uppercase tracking-tighter">{p.name} {p.wasCaller && <span className="text-[9px] bg-yellow-500 text-black px-1.5 py-0.5 rounded ml-2 font-black">CALLER</span>}</span>
                   <div className="text-right">
                      <div className="text-xl font-black text-yellow-500">+{p.score}</div>
                      <div className="text-[9px] text-gray-500 font-bold">TOTAL: {p.totalScore}</div>
                   </div>
                </div>
              ))}
           </div>
           {gameState.roundNumber < gameState.totalRounds ? (
             <button onClick={() => startRound(gameState.roundNumber + 1, gameState.players)} className="w-full max-w-xs bg-white text-black font-black py-4 rounded-2xl flex items-center justify-center gap-3 hover:bg-yellow-500 transition-all uppercase tracking-widest text-sm">Next Round <ChevronRight size={20}/></button>
           ) : (
             <button onClick={clearSession} className="w-full max-w-xs bg-slate-700 text-white font-black py-4 rounded-2xl hover:bg-slate-600 transition-all uppercase tracking-widest text-sm">Finish Match</button>
           )}
        </div>
      )}

      {/* Round Selection Modal */}
      {showRoundSelectionSP && (
        <div className="fixed inset-0 z-[60] bg-black/80 flex items-center justify-center p-4 backdrop-blur-sm">
           <div className="bg-slate-900 border border-white/10 p-8 rounded-3xl w-full max-w-xs text-center">
              <h2 className="text-xl font-serif font-bold text-white mb-6">Match Length</h2>
              <div className="grid grid-cols-2 gap-3 mb-8">
                 {[1, 3, 5, 10].map(r => (
                   <button key={r} onClick={() => startSinglePlayer(r)} className="bg-slate-800 hover:bg-blue-600 text-white font-bold py-4 rounded-xl border border-white/5 transition-all">{r} Round{r>1?'s':''}</button>
                 ))}
              </div>
              <button onClick={() => setShowRoundSelectionSP(false)} className="text-gray-500 text-sm font-bold uppercase tracking-widest hover:text-white">Cancel</button>
           </div>
        </div>
      )}

      {/* Online Selection Modal */}
      {showOnlineSelection && (
        <div className="fixed inset-0 z-[60] bg-black/80 flex items-center justify-center p-4 backdrop-blur-sm">
           <div className="bg-slate-900 border border-white/10 p-8 rounded-3xl w-full max-w-md text-center">
              <h2 className="text-2xl font-serif font-bold text-white mb-8 tracking-tight">Online Multiplayer</h2>
              <button onClick={handleCreateOnline} className="w-full bg-purple-600 hover:bg-purple-500 text-white font-bold py-5 rounded-2xl mb-6 flex items-center justify-center gap-3 transition-all"><Play size={20}/> Create New Room</button>
              <div className="flex items-center gap-4 mb-6"><div className="h-px bg-white/10 flex-1"/> <span className="text-[10px] text-gray-500 font-bold tracking-widest">OR JOIN ROOM</span> <div className="h-px bg-white/10 flex-1"/></div>
              <div className="flex gap-2 mb-8">
                 <input value={joinCodeInput} onChange={e => setJoinCodeInput(e.target.value.toUpperCase())} maxLength={4} placeholder="CODE" className="flex-1 bg-black/40 border border-white/10 text-white text-center text-xl font-mono tracking-[0.5em] py-4 rounded-2xl focus:border-purple-500 outline-none"/>
                 <button onClick={handleJoinOnline} disabled={isJoining || joinCodeInput.length !== 4} className="bg-white hover:bg-yellow-500 text-black px-6 rounded-2xl font-black disabled:opacity-30 transition-all">{isJoining ? <RefreshCw className="animate-spin"/> : 'JOIN'}</button>
              </div>
              <button onClick={() => setShowOnlineSelection(false)} className="text-gray-500 text-xs font-bold uppercase tracking-widest hover:text-white">Back to Menu</button>
           </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { GameState, Player, CardData, GamePhase, GameMode } from './types';
import { createDeck, getRoundScores, calculateHandValue, decideBotAction, shuffleDeck } from './services/gameLogic';
import { createRoom, joinRoom, subscribeToRoom, updateGameState, getRoomData } from './services/online';
import { DEFAULT_TOTAL_ROUNDS } from './constants';
import Card from './components/Card';
import Auth from './components/Auth';
import { supabase, signOut } from './services/supabase';
import { 
  RefreshCw, Trophy, Users, Hand, ChevronRight, EyeOff, Eye, 
  User, Bot, Play, Sparkles, LogOut, Globe, Copy, X, Loader2
} from 'lucide-react';

const SESSION_KEY = 'TRI_STACK_SESSION';
const NAME_KEY = 'TRI_STACK_PLAYER_NAME';
const TUTORIAL_KEY = 'TRI_STACK_TUTORIAL_COMPLETE_V6';

// --- Sub-components (outside for stability) ---

interface TutorialOverlayProps {
  step: number;
  onSkip: () => void;
  onNext: () => void;
}

const TutorialOverlay: React.FC<TutorialOverlayProps> = ({ step, onSkip, onNext }) => {
  if (step === 0) return null;

  let message = "";
  switch(step) {
    case 1: message = "Welcome! Your goal is to get your hand total as close to 0 as possible."; break;
    case 2: message = "Tap a card in your hand to select it for discarding."; break;
    case 3: message = "Now tap the DISCARD button to remove it."; break;
    case 4: message = "Every discard needs a draw. Tap the DECK to pick up a new card."; break;
    case 5: message = "When your total is 5 or less, tap SHOW to end the round. Good luck!"; break;
  }

  return (
    <div className="fixed inset-0 z-[100] flex flex-col items-center justify-center pointer-events-none">
      <div className="absolute inset-0 bg-black/80 backdrop-blur-[2px] pointer-events-auto" />

      <div className="relative z-[110] bg-slate-900 border-2 border-yellow-500 p-6 rounded-2xl shadow-2xl max-w-xs text-center animate-in zoom-in fade-in pointer-events-auto">
        <div className="flex justify-between items-start mb-4">
          <div className="bg-yellow-500 text-black px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-widest">Guide {step}/5</div>
          <button onClick={onSkip} className="text-gray-500 hover:text-white"><X size={18} /></button>
        </div>
        <p className="text-white font-bold mb-6 text-lg leading-tight">{message}</p>
        <div className="flex flex-col gap-2">
          {(step === 1 || step === 5) && (
            <button onClick={onNext} className="bg-yellow-500 hover:bg-yellow-400 text-black font-bold py-3 rounded-xl transition-all flex items-center justify-center gap-2">
              {step === 5 ? "Start Playing!" : "Next Step"} <ChevronRight size={18} />
            </button>
          )}
          <button onClick={onSkip} className="text-gray-400 text-xs hover:text-white py-2">Skip Tutorial</button>
        </div>
      </div>

      <style>{`
        ${step === 2 ? '.hand-area { z-index: 110 !important; position: relative; box-shadow: 0 0 50px rgba(234, 179, 8, 0.4); border-radius: 20px; }' : ''}
        ${step === 3 ? '.controls-area { z-index: 110 !important; position: relative; box-shadow: 0 0 50px rgba(234, 179, 8, 0.4); border-radius: 20px; }' : ''}
        ${step === 4 ? '.deck-area { z-index: 110 !important; position: relative; box-shadow: 0 0 50px rgba(234, 179, 8, 0.4); border-radius: 20px; }' : ''}
      `}</style>
    </div>
  );
};

// --- Main App Component ---

const App: React.FC = () => {
  // --- Auth State ---
  const [session, setSession] = useState<any>(null);
  const [isGuest, setIsGuest] = useState(false);
  const [authLoading, setAuthLoading] = useState(true);

  // --- Tutorial State ---
  const [hasSeenTutorial, setHasSeenTutorial] = useState<boolean>(() => {
    try { return localStorage.getItem(TUTORIAL_KEY) === 'true'; } catch { return false; }
  });
  const [tutorialStep, setTutorialStep] = useState(0);

  // --- Game State ---
  const [gameState, setGameState] = useState<GameState>({
    gameMode: null, deck: [], openDeck: [], players: [], currentPlayerIndex: 0,
    roundJoker: null, roundNumber: 1, totalRounds: DEFAULT_TOTAL_ROUNDS,
    phase: GamePhase.SETUP, turnLog: [], winner: null, lastDiscardedId: null,
    tossedThisTurn: false, pendingDiscard: null, pendingToss: [], playerNames: []
  });

  const [selectedCardIds, setSelectedCardIds] = useState<string[]>([]);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [showOnlineSelection, setShowOnlineSelection] = useState(false); 
  const [showRoundSelectionSP, setShowRoundSelectionSP] = useState(false);
  const [selectedTotalRounds, setSelectedTotalRounds] = useState(DEFAULT_TOTAL_ROUNDS);
  const [customDisplayName, setCustomDisplayName] = useState('');

  // Online Specific State
  const [roomCode, setRoomCode] = useState('');
  const [joinCodeInput, setJoinCodeInput] = useState('');
  const [myOnlineId, setMyOnlineId] = useState<number | null>(null); 
  const [onlineLobbyPlayers, setOnlineLobbyPlayers] = useState<{id: number, name: string}[]>([]);
  const [isOnlineLobby, setIsOnlineLobby] = useState(false);
  const [isReconnecting, setIsReconnecting] = useState(false); 
  const [isJoining, setIsJoining] = useState(false); 

  // --- Auth Effect ---
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setAuthLoading(false);
    }).catch(() => setAuthLoading(false));

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });
    return () => subscription.unsubscribe();
  }, []);

  // --- Load Custom Name ---
  useEffect(() => {
    try {
      const savedName = localStorage.getItem(NAME_KEY);
      if (savedName) setCustomDisplayName(savedName);
    } catch (e) {}
  }, []);

  const getDisplayName = useCallback(() => {
    if (customDisplayName) return customDisplayName;
    return isGuest ? 'Guest' : (session?.user?.email?.split('@')[0] || 'Player');
  }, [customDisplayName, isGuest, session]);

  // --- Tutorial Steps ---
  const skipTutorial = () => {
    setTutorialStep(0);
    setHasSeenTutorial(true);
    try { localStorage.setItem(TUTORIAL_KEY, 'true'); } catch {}
  };

  const advanceTutorial = () => {
    if (tutorialStep === 5) skipTutorial();
    else setTutorialStep(prev => prev + 1);
  };

  // Auto-advance tutorial logic
  useEffect(() => {
    if (tutorialStep === 2 && selectedCardIds.length > 0) setTutorialStep(3);
    if (tutorialStep === 3 && gameState.phase === GamePhase.PLAYER_DRAW) setTutorialStep(4);
    if (tutorialStep === 4 && gameState.phase === GamePhase.PLAYER_TURN_START && gameState.currentPlayerIndex !== 0) {
      setTutorialStep(5);
    }
  }, [tutorialStep, selectedCardIds, gameState.phase, gameState.currentPlayerIndex]);

  // --- Start Round Core Logic ---
  const startRound = useCallback((roundNum: number, existingPlayers?: Player[], mode?: GameMode) => {
    const newDeck = createDeck();
    const roundJoker = { ...newDeck[Math.floor(Math.random() * newDeck.length)] };
    let players: Player[] = [];

    if (existingPlayers && existingPlayers.length > 0) {
      players = existingPlayers.map(p => ({ 
        ...p, hand: [], score: 0, lastAction: 'Waiting...', wasCaller: false 
      }));
    } else {
      const names = [getDisplayName(), 'Bot Alpha', 'Bot Beta', 'Bot Gamma'];
      players = names.map((n, i) => ({
        id: i, name: n, isBot: i > 0, hand: [], score: 0, totalScore: 0, lastAction: 'Waiting...'
      }));
    }

    players.forEach(p => { p.hand = newDeck.splice(0, 3); });

    setGameState(prev => {
      const targetMode = mode || prev.gameMode;
      const newState: GameState = {
        ...prev,
        deck: newDeck,
        openDeck: [],
        players,
        currentPlayerIndex: 0,
        roundJoker,
        roundNumber: roundNum,
        totalRounds: selectedTotalRounds,
        phase: GamePhase.PLAYER_TURN_START,
        tossedThisTurn: false,
        gameMode: targetMode,
        pendingDiscard: null,
        pendingToss: []
      };
      // If host, sync
      if (targetMode === 'ONLINE_HOST' && roomCode) updateGameState(roomCode, newState);
      return newState;
    });

    setSelectedCardIds([]);
  }, [getDisplayName, selectedTotalRounds, roomCode]);

  // --- Game Selection Handlers ---
  const startSinglePlayer = (rounds: number) => {
    setSelectedTotalRounds(rounds);
    setGameState(prev => ({ 
      ...prev, 
      gameMode: 'SINGLE_PLAYER', 
      phase: GamePhase.SETUP,
      players: [] // Clear to force restart
    }));
    setShowRoundSelectionSP(false);
    if (!hasSeenTutorial) setTutorialStep(1);
  };

  // Trigger round start when SETUP is detected
  useEffect(() => {
    if (gameState.phase === GamePhase.SETUP && gameState.gameMode && !gameState.gameMode.startsWith('ONLINE')) {
      startRound(1, undefined, gameState.gameMode);
    }
  }, [gameState.phase, gameState.gameMode, startRound]);

  // --- Online Connection Effects ---
  useEffect(() => {
    const checkSession = async () => {
      try {
        const savedSession = localStorage.getItem(SESSION_KEY);
        if (savedSession) {
          setIsReconnecting(true);
          const { code, playerId } = JSON.parse(savedSession);
          const { data: roomData, error } = await getRoomData(code);
          if (error || !roomData) {
             localStorage.removeItem(SESSION_KEY);
             setIsReconnecting(false);
             return;
          }
          setRoomCode(code);
          setMyOnlineId(playerId);
          setIsGuest(true);
          if (roomData.status === 'WAITING') {
            setOnlineLobbyPlayers(roomData.players || []);
            setIsOnlineLobby(true);
          } else if (roomData.game_state) {
            setGameState({ ...roomData.game_state, gameMode: (playerId === 0 ? 'ONLINE_HOST' : 'ONLINE_CLIENT') });
          }
        }
      } catch (e) {
        localStorage.removeItem(SESSION_KEY);
      } finally {
        setIsReconnecting(false);
      }
    };
    checkSession();
  }, []);

  useEffect(() => {
    if (!roomCode) return;
    const subscription = subscribeToRoom(roomCode, (roomData) => {
      if (roomData.status === 'WAITING') {
         setOnlineLobbyPlayers(roomData.players || []);
      } else if (roomData.game_state) {
         setGameState({ ...roomData.game_state, gameMode: (myOnlineId === 0 ? 'ONLINE_HOST' : 'ONLINE_CLIENT') });
         setIsOnlineLobby(false);
         setShowOnlineSelection(false);
      }
    });
    return () => { supabase.removeChannel(subscription); };
  }, [roomCode, myOnlineId]);

  const clearSession = () => {
    localStorage.removeItem(SESSION_KEY);
    setRoomCode('');
    setMyOnlineId(null);
    setIsOnlineLobby(false);
    setGameState({
      gameMode: null, deck: [], openDeck: [], players: [], currentPlayerIndex: 0,
      roundJoker: null, roundNumber: 1, totalRounds: DEFAULT_TOTAL_ROUNDS,
      phase: GamePhase.SETUP, turnLog: [], winner: null, lastDiscardedId: null,
      tossedThisTurn: false, pendingDiscard: null, pendingToss: [], playerNames: []
    });
    setSelectedCardIds([]);
    setIsTransitioning(false);
  };

  // --- Derived State for Rendering ---
  const currentPlayer = gameState.players[gameState.currentPlayerIndex] || null;
  const bottomPlayer = (gameState.gameMode === 'SINGLE_PLAYER' || (gameState.gameMode?.startsWith('ONLINE') && myOnlineId !== null))
    ? (gameState.players.find(p => p.id === (myOnlineId ?? 0)) || currentPlayer)
    : currentPlayer;

  const opponents = gameState.players.filter(p => p.id !== (bottomPlayer?.id ?? -1));
  const isMyTurn = (gameState.gameMode?.startsWith('ONLINE')) ? (currentPlayer?.id === myOnlineId) : true;
  const isPlayerTurn = !isTransitioning && currentPlayer && !currentPlayer.isBot && gameState.phase !== GamePhase.ROUND_END && isMyTurn;
  const isBotThinking = gameState.gameMode === 'SINGLE_PLAYER' && currentPlayer?.isBot && !isTransitioning && gameState.phase !== GamePhase.ROUND_END;

  // --- Bot Effect ---
  useEffect(() => {
    if (!isBotThinking || !currentPlayer) return;
    const timeout = setTimeout(() => {
      setGameState(prev => {
        let newState = { ...prev };
        const curr = newState.players[newState.currentPlayerIndex];

        if (newState.phase === GamePhase.PLAYER_TURN_START) {
          const action = decideBotAction(curr, newState.roundJoker, newState.tossedThisTurn);
          if (action.type === 'SHOW') {
             const results = getRoundScores(newState.players, newState.currentPlayerIndex, newState.roundJoker);
             newState.players = newState.players.map(pl => {
               const res = results.find(r => r.playerId === pl.id);
               return { ...pl, score: res?.roundScore || 0, totalScore: pl.totalScore + (res?.roundScore || 0), wasCaller: pl.id === curr.id };
             });
             newState.phase = GamePhase.ROUND_END;
          } else if (action.type === 'TOSS') {
             const cards = curr.hand.filter(c => action.cardIds?.includes(c.id));
             newState.players = newState.players.map(pl => pl.id === curr.id ? { ...pl, hand: pl.hand.filter(c => !action.cardIds?.includes(c.id)) } : pl);
             newState.pendingToss = cards; newState.phase = GamePhase.PLAYER_TOSSING_DRAW; newState.tossedThisTurn = true;
          } else {
             const card = curr.hand.find(c => c.id === action.cardIds![0])!;
             newState.players = newState.players.map(pl => pl.id === curr.id ? { ...pl, hand: pl.hand.filter(c => c.id !== card.id) } : pl);
             newState.pendingDiscard = card; newState.lastDiscardedId = card.id; newState.phase = GamePhase.PLAYER_DRAW;
          }
        } else {
          const drawn = newState.deck.shift()!;
          newState.players = newState.players.map(pl => pl.id === curr.id ? { ...pl, hand: [...pl.hand, drawn] } : pl);
          if (newState.pendingToss.length) newState.openDeck = [...newState.openDeck, ...newState.pendingToss];
          if (newState.pendingDiscard) newState.openDeck = [...newState.openDeck, newState.pendingDiscard];
          newState.pendingToss = []; newState.pendingDiscard = null;
          newState.currentPlayerIndex = (newState.currentPlayerIndex + 1) % newState.players.length;
          newState.phase = GamePhase.PLAYER_TURN_START; newState.tossedThisTurn = false;
        }
        return newState;
      });
    }, 1200);
    return () => clearTimeout(timeout);
  }, [isBotThinking, currentPlayer?.id, gameState.phase]);

  // --- Action Handlers ---
  const handleCardClick = (card: CardData) => {
    if (!isPlayerTurn) return;
    setSelectedCardIds(prev => prev.includes(card.id) ? prev.filter(id => id !== card.id) : (prev.length >= 2 ? [prev[1], card.id] : [...prev, card.id]));
  };

  const handleDiscard = () => {
    if (selectedCardIds.length !== 1 || !bottomPlayer) return;
    const card = bottomPlayer.hand.find(c => c.id === selectedCardIds[0])!;
    setGameState(prev => {
      const newState = {
        ...prev, 
        players: prev.players.map(pl => pl.id === bottomPlayer.id ? { ...pl, hand: pl.hand.filter(c => c.id !== card.id) } : pl),
        pendingDiscard: card, lastDiscardedId: card.id, phase: GamePhase.PLAYER_DRAW
      };
      if (roomCode) updateGameState(roomCode, newState);
      return newState;
    });
    setSelectedCardIds([]);
  };

  const handleDraw = (source: 'DECK' | 'OPEN') => {
    if (!bottomPlayer) return;
    setGameState(prev => {
      let drawn: CardData;
      let newDeck = [...prev.deck];
      let newOpen = [...prev.openDeck];
      if (source === 'OPEN') {
        if (newOpen.length === 0) return prev;
        drawn = newOpen.pop()!;
      } else {
        if (newDeck.length === 0) {
          if (newOpen.length <= 1) return prev; // Stall prevention
          const top = newOpen.pop()!;
          newDeck = shuffleDeck(newOpen);
          newOpen = [top];
        }
        drawn = newDeck.shift()!;
      }
      const nextIdx = (prev.currentPlayerIndex + 1) % prev.players.length;
      const newState = {
        ...prev, deck: newDeck, openDeck: [...newOpen, ...(prev.pendingToss), ...(prev.pendingDiscard ? [prev.pendingDiscard] : [])],
        players: prev.players.map(pl => pl.id === bottomPlayer.id ? { ...pl, hand: [...pl.hand, drawn] } : pl),
        currentPlayerIndex: nextIdx, phase: GamePhase.PLAYER_TURN_START, tossedThisTurn: false, pendingDiscard: null, pendingToss: []
      };
      if (roomCode) updateGameState(roomCode, newState);
      return newState;
    });
  };

  const handleShow = () => {
    if (!currentPlayer) return;
    const res = getRoundScores(gameState.players, gameState.currentPlayerIndex, gameState.roundJoker);
    const newState = {
      ...gameState, phase: GamePhase.ROUND_END,
      players: gameState.players.map(pl => {
        const r = res.find(i => i.playerId === pl.id);
        return { ...pl, score: r?.roundScore || 0, totalScore: pl.totalScore + (r?.roundScore || 0), wasCaller: pl.id === currentPlayer.id };
      })
    };
    setGameState(newState); if (roomCode) updateGameState(roomCode, newState);
  };

  const handleCreateOnline = async () => {
    const { code, error } = await createRoom(getDisplayName(), session?.user?.id || 'guest');
    if (error) return alert("Error creating room");
    setRoomCode(code);
    setMyOnlineId(0);
    localStorage.setItem(SESSION_KEY, JSON.stringify({ code, playerId: 0 }));
    setOnlineLobbyPlayers([{ id: 0, name: getDisplayName() }]);
    setIsOnlineLobby(true);
  };

  const handleJoinOnline = async () => {
    if (joinCodeInput.length !== 4) return;
    setIsJoining(true);
    const { success, error, playerId, players } = await joinRoom(joinCodeInput.toUpperCase(), getDisplayName());
    if (!success) {
      alert(error);
      setIsJoining(false);
      return;
    }
    setRoomCode(joinCodeInput.toUpperCase());
    setMyOnlineId(playerId!);
    localStorage.setItem(SESSION_KEY, JSON.stringify({ code: joinCodeInput.toUpperCase(), playerId }));
    setOnlineLobbyPlayers(players!);
    setIsOnlineLobby(true);
    setIsJoining(false);
  };

  // --- Auth & Initial Loads ---
  if (authLoading || isReconnecting) return <div className="h-screen bg-[#1a2e1a] flex flex-col items-center justify-center text-white gap-4"><RefreshCw className="animate-spin text-yellow-500" size={48} /><h2 className="font-serif text-2xl">Loading Tri-Stack...</h2></div>;
  if (!session && !isGuest) return <Auth onGuestPlay={() => setIsGuest(true)} />;

  // Lobby UI
  if (isOnlineLobby) {
    return (
      <div className="h-screen bg-[#1a2e1a] flex flex-col items-center justify-center p-4">
        <div className="bg-slate-900/90 p-8 rounded-2xl border border-yellow-500/30 w-full max-w-md text-center">
          <h1 className="text-3xl font-serif font-bold text-yellow-500 mb-6 tracking-tight uppercase">Room Lobby</h1>
          <div className="bg-black/40 p-4 rounded-xl mb-6 flex items-center justify-between border border-white/10">
            <div className="text-left">
              <p className="text-[10px] text-gray-400 uppercase font-bold tracking-widest">Code</p>
              <p className="text-3xl font-mono font-bold text-white tracking-widest">{roomCode}</p>
            </div>
            <button onClick={() => navigator.clipboard.writeText(roomCode)} className="bg-slate-700 p-2 rounded hover:bg-slate-600 transition-colors"><Copy size={20} className="text-gray-300" /></button>
          </div>
          <div className="mb-8">
            <h3 className="text-xs font-bold text-gray-500 mb-4 uppercase tracking-widest flex items-center justify-center gap-2">Players Connected</h3>
            <div className="flex flex-col gap-2">
              {onlineLobbyPlayers.map(p => (
                <div key={p.id} className="bg-slate-800 p-3 rounded-lg flex items-center justify-between border border-white/5">
                  <span className="font-bold text-white">{p.name}</span>
                  {p.id === 0 && <span className="text-[9px] bg-yellow-500 text-black px-2 py-0.5 rounded font-black">HOST</span>}
                </div>
              ))}
            </div>
          </div>
          <div className="flex flex-col gap-3">
            {myOnlineId === 0 ? (
              <button onClick={() => startRound(1, undefined, 'ONLINE_HOST')} disabled={onlineLobbyPlayers.length < 2} className="w-full bg-green-600 hover:bg-green-500 text-white font-bold py-4 rounded-xl flex items-center justify-center gap-2 disabled:opacity-50 transition-all">Start Match <Play size={20} /></button>
            ) : (
              <div className="w-full bg-slate-800 text-gray-500 font-bold py-4 rounded-xl flex items-center justify-center gap-2 animate-pulse">Waiting for host...</div>
            )}
            <button onClick={clearSession} className="text-red-400 text-sm font-bold hover:underline mt-2">Leave Room</button>
          </div>
        </div>
      </div>
    );
  }

  // Menu UI
  if (!gameState.gameMode && !showRoundSelectionSP && !showOnlineSelection) {
    return (
      <div className="h-screen bg-[#1a2e1a] flex flex-col items-center justify-center p-4">
        <h1 className="font-serif text-5xl md:text-7xl font-bold text-yellow-500 mb-12 drop-shadow-2xl">TRI-STACK</h1>
        <div className="bg-slate-900/40 p-8 rounded-3xl backdrop-blur-md border border-white/5 shadow-2xl flex flex-col gap-5 w-full max-w-md">
           <button onClick={() => setShowRoundSelectionSP(true)} className="bg-blue-600 hover:bg-blue-500 text-white p-6 rounded-2xl font-bold text-lg flex items-center gap-4 transition-all transform hover:scale-[1.02]">
             <div className="w-12 h-12 bg-blue-800 rounded-full flex items-center justify-center shadow-inner"><User size={24} /></div>
             <div className="text-left"><div>Single Player</div><div className="text-xs text-blue-200 font-normal">Train against Bots</div></div>
           </button>
           <button onClick={() => setShowOnlineSelection(true)} className="bg-purple-600 hover:bg-purple-500 text-white p-6 rounded-2xl font-bold text-lg flex items-center gap-4 transition-all transform hover:scale-[1.02]">
             <div className="w-12 h-12 bg-purple-800 rounded-full flex items-center justify-center shadow-inner"><Globe size={24} /></div>
             <div className="text-left"><div>Online Play</div><div className="text-xs text-purple-200 font-normal">Play with Friends</div></div>
           </button>
        </div>
      </div>
    );
  }

  // Handle Board Setup Frame (dealing)
  if (gameState.gameMode && gameState.phase === GamePhase.SETUP) {
    return (
      <div className="h-screen bg-[#1a2e1a] flex flex-col items-center justify-center text-white gap-6">
        <div className="relative">
          <RefreshCw className="animate-spin text-yellow-500" size={64} />
          <div className="absolute inset-0 flex items-center justify-center">
            <Hand size={24} className="text-white" />
          </div>
        </div>
        <div className="text-center">
          <h2 className="font-serif text-3xl font-bold text-white mb-2 uppercase tracking-widest">Shuffling</h2>
          <p className="text-yellow-500 text-xs font-black tracking-[0.3em] uppercase animate-pulse">Dealing Hands...</p>
        </div>
      </div>
    );
  }

  // Final Safety check before game board
  if (!gameState.gameMode || !bottomPlayer) return null;

  return (
    <div className="h-screen flex flex-col overflow-hidden bg-[#1a2e1a] select-none">
      <TutorialOverlay step={tutorialStep} onSkip={skipTutorial} onNext={advanceTutorial} />

      {/* Header */}
      <div className="h-14 bg-black/40 backdrop-blur flex items-center justify-between px-4 z-20 border-b border-white/5">
        <div className="flex items-center gap-3">
          <button onClick={clearSession} className="text-red-400 bg-white/5 p-2 rounded-lg"><LogOut size={18} /></button>
          <div className="bg-white/10 px-3 py-1 rounded-full text-[10px] font-black text-white tracking-widest">ROUND {gameState.roundNumber}/{gameState.totalRounds}</div>
        </div>
        <div className="flex items-center gap-2">
          <Sparkles size={14} className="text-yellow-500 animate-pulse" />
          <span className="text-xs font-black text-yellow-500 uppercase tracking-tighter">{gameState.roundJoker?.rank} JOKER</span>
        </div>
      </div>

      <div className="flex-1 flex flex-col justify-between p-2 max-w-xl mx-auto w-full relative">
        {/* Opponents */}
        <div className="flex justify-center gap-3 mt-2">
           {opponents.map(opp => (
             <div key={opp.id} className={`flex flex-col items-center p-2 rounded-xl transition-all ${opp.id === gameState.currentPlayerIndex ? 'bg-yellow-500/10 ring-1 ring-yellow-500/50 scale-105 shadow-[0_0_15px_rgba(234,179,8,0.2)]' : 'bg-black/20'}`}>
                <div className={`w-8 h-8 rounded-full flex items-center justify-center border ${opp.id === gameState.currentPlayerIndex ? 'bg-yellow-500 text-black border-yellow-400' : 'bg-slate-700 text-slate-400 border-white/5'}`}>{opp.isBot ? <Bot size={16} /> : <User size={16} />}</div>
                <span className="text-[9px] font-bold mt-1 text-white/80 uppercase tracking-tighter max-w-[45px] truncate">{opp.name}</span>
                <span className="text-[10px] text-yellow-500 font-black">{opp.totalScore}</span>
             </div>
           ))}
        </div>

        {/* Board */}
        <div className="flex items-center justify-center gap-10 deck-area py-6">
           <div className="flex flex-col items-center gap-2">
             <Card 
               onClick={() => (gameState.phase === GamePhase.PLAYER_DRAW || gameState.phase === GamePhase.PLAYER_TOSSING_DRAW) && handleDraw('DECK')} 
               disabled={gameState.phase === GamePhase.PLAYER_TURN_START}
             />
             <span className="text-[9px] font-black text-gray-500 tracking-widest uppercase">Deck</span>
           </div>
           <div className="flex flex-col items-center gap-2">
              {gameState.openDeck.length > 0 ? (
                <Card 
                  card={gameState.openDeck[gameState.openDeck.length - 1]} 
                  onClick={() => (gameState.phase === GamePhase.PLAYER_DRAW || gameState.phase === GamePhase.PLAYER_TOSSING_DRAW) && handleDraw('OPEN')}
                  disabled={gameState.phase === GamePhase.PLAYER_TURN_START}
                />
              ) : (
                <div className="w-16 h-24 border border-dashed border-white/10 rounded-xl flex items-center justify-center">
                   <span className="text-[8px] text-white/10 font-black uppercase text-center">Empty</span>
                </div>
              )}
              <span className="text-[9px] font-black text-gray-500 tracking-widest uppercase">Discard</span>
           </div>
        </div>

        {/* Action Area */}
        <div className="flex flex-col items-center gap-4 mb-4">
           {isPlayerTurn && (
             <div className="bg-yellow-500/20 px-6 py-1.5 rounded-full border border-yellow-500/30 animate-pulse">
               <span className="text-yellow-500 font-black text-[10px] uppercase tracking-[0.2em]">Your Turn</span>
             </div>
           )}

           <div className="flex gap-4 controls-area">
              <button 
                onClick={handleDiscard}
                disabled={!isPlayerTurn || gameState.phase !== GamePhase.PLAYER_TURN_START || selectedCardIds.length !== 1}
                className={`w-20 h-16 rounded-2xl flex flex-col items-center justify-center gap-1 font-black transition-all border-b-4 ${selectedCardIds.length === 1 ? 'bg-slate-700 text-white border-slate-900 scale-110 shadow-xl' : 'bg-slate-800 text-slate-600 border-slate-950 opacity-40'}`}
              >
                 <RefreshCw size={18} /> <span className="text-[9px] uppercase tracking-widest">Discard</span>
              </button>
              <button 
                onClick={handleShow}
                disabled={!isPlayerTurn || gameState.phase !== GamePhase.PLAYER_TURN_START || calculateHandValue(bottomPlayer.hand, gameState.roundJoker) > 5}
                className={`w-20 h-16 rounded-2xl flex flex-col items-center justify-center gap-1 font-black transition-all border-b-4 ${isPlayerTurn && gameState.phase === GamePhase.PLAYER_TURN_START && calculateHandValue(bottomPlayer.hand, gameState.roundJoker) <= 5 ? 'bg-yellow-500 text-black border-yellow-700 scale-125 shadow-2xl' : 'bg-slate-800 text-slate-600 border-slate-950 opacity-40'}`}
              >
                 <Eye size={18} /> <span className="text-[9px] uppercase tracking-widest">Show</span>
              </button>
           </div>
        </div>

        {/* Hand */}
        <div className="flex flex-col items-center hand-area pb-4">
           <div className="flex justify-center gap-2 h-40 items-end">
              {bottomPlayer.hand.map(card => (
                <Card 
                  key={card.id} card={card} 
                  selected={selectedCardIds.includes(card.id)} 
                  onClick={() => handleCardClick(card)}
                  isJoker={card.rank === gameState.roundJoker?.rank}
                  disabled={!isPlayerTurn || gameState.phase !== GamePhase.PLAYER_TURN_START}
                />
              ))}
           </div>
           <div className="mt-4 bg-black/40 px-5 py-1.5 rounded-full text-[10px] font-black text-white/60 tracking-widest border border-white/5">
              SCORE: <span className="text-yellow-500">{calculateHandValue(bottomPlayer.hand, gameState.roundJoker)}</span>
           </div>
        </div>
      </div>

      {/* Round End Overlay */}
      {gameState.phase === GamePhase.ROUND_END && (
        <div className="fixed inset-0 z-50 bg-black/95 flex flex-col items-center justify-center p-6 animate-in fade-in zoom-in duration-300">
           <Trophy className="text-yellow-500 mb-6 drop-shadow-[0_0_30px_rgba(234,179,8,0.5)]" size={80} />
           <h2 className="text-3xl font-serif font-bold text-white mb-8 tracking-tight">Round Results</h2>
           <div className="w-full max-w-sm flex flex-col gap-3 mb-10">
              {gameState.players.sort((a,b) => a.score - b.score).map(p => (
                <div key={p.id} className={`flex items-center justify-between p-4 rounded-2xl border ${p.wasCaller ? 'bg-yellow-500/10 border-yellow-500/50' : 'bg-white/5 border-white/5'}`}>
                   <span className="font-bold text-white text-sm uppercase tracking-tighter">{p.name} {p.wasCaller && <span className="text-[9px] bg-yellow-500 text-black px-1.5 py-0.5 rounded ml-2 font-black">CALLER</span>}</span>
                   <div className="text-right">
                      <div className="text-xl font-black text-yellow-500">+{p.score}</div>
                      <div className="text-[9px] text-gray-500 font-bold">TOTAL: {p.totalScore}</div>
                   </div>
                </div>
              ))}
           </div>
           {gameState.roundNumber < gameState.totalRounds ? (
             <button onClick={() => startRound(gameState.roundNumber + 1, gameState.players)} className="w-full max-w-xs bg-white text-black font-black py-4 rounded-2xl flex items-center justify-center gap-3 hover:bg-yellow-500 transition-all uppercase tracking-widest text-sm">Next Round <ChevronRight size={20}/></button>
           ) : (
             <button onClick={clearSession} className="w-full max-w-xs bg-slate-700 text-white font-black py-4 rounded-2xl hover:bg-slate-600 transition-all uppercase tracking-widest text-sm">Finish Match</button>
           )}
        </div>
      )}

      {/* Round Selection Modal */}
      {showRoundSelectionSP && (
        <div className="fixed inset-0 z-[60] bg-black/80 flex items-center justify-center p-4 backdrop-blur-sm">
           <div className="bg-slate-900 border border-white/10 p-8 rounded-3xl w-full max-w-xs text-center">
              <h2 className="text-xl font-serif font-bold text-white mb-6 tracking-tight uppercase">Match Length</h2>
              <div className="grid grid-cols-2 gap-3 mb-8">
                 {[1, 3, 5, 10].map(r => (
                   <button key={r} onClick={() => startSinglePlayer(r)} className="bg-slate-800 hover:bg-blue-600 text-white font-bold py-4 rounded-xl border border-white/5 transition-all text-sm uppercase tracking-widest">{r} {r>1?'Rounds':'Round'}</button>
                 ))}
              </div>
              <button onClick={() => setShowRoundSelectionSP(false)} className="text-gray-500 text-[10px] font-black uppercase tracking-[0.2em] hover:text-white">Cancel</button>
           </div>
        </div>
      )}

      {/* Online Selection Modal */}
      {showOnlineSelection && (
        <div className="fixed inset-0 z-[60] bg-black/80 flex items-center justify-center p-4 backdrop-blur-sm">
           <div className="bg-slate-900 border border-white/10 p-8 rounded-3xl w-full max-w-md text-center">
              <h2 className="text-2xl font-serif font-bold text-white mb-8 tracking-tight">Online Multiplayer</h2>
              <button onClick={handleCreateOnline} className="w-full bg-purple-600 hover:bg-purple-500 text-white font-bold py-5 rounded-2xl mb-6 flex items-center justify-center gap-3 transition-all"><Play size={20}/> Create New Room</button>
              <div className="flex items-center gap-4 mb-6"><div className="h-px bg-white/10 flex-1"/> <span className="text-[10px] text-gray-500 font-bold tracking-widest uppercase">OR</span> <div className="h-px bg-white/10 flex-1"/></div>
              <div className="flex gap-2 mb-8">
                 <input value={joinCodeInput} onChange={e => setJoinCodeInput(e.target.value.toUpperCase())} maxLength={4} placeholder="CODE" className="flex-1 bg-black/40 border border-white/10 text-white text-center text-xl font-mono tracking-[0.5em] py-4 rounded-2xl focus:border-purple-500 outline-none uppercase placeholder:text-gray-700"/>
                 <button onClick={handleJoinOnline} disabled={isJoining || joinCodeInput.length !== 4} className="bg-white hover:bg-yellow-500 text-black px-6 rounded-2xl font-black disabled:opacity-30 transition-all">{isJoining ? <Loader2 className="animate-spin"/> : 'JOIN'}</button>
              </div>
              <button onClick={() => setShowOnlineSelection(false)} className="text-gray-500 text-[10px] font-black uppercase tracking-[0.2em] hover:text-white">Back to Menu</button>
           </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { GameState, Player, CardData, GamePhase, GameMode } from './types';
import { createDeck, getRoundScores, calculateHandValue, decideBotAction, shuffleDeck } from './services/gameLogic';
import { createRoom, joinRoom, subscribeToRoom, updateGameState, getRoomData } from './services/online';
import { DEFAULT_TOTAL_ROUNDS } from './constants';
import Card from './components/Card';
import Auth from './components/Auth';
import { supabase, signOut } from './services/supabase';
import { 
  RefreshCw, Trophy, Users, Hand, ChevronRight, EyeOff, Eye, 
  User, Bot, Play, Sparkles, LogOut, Globe, Copy, X, Loader2
} from 'lucide-react';

const SESSION_KEY = 'TRI_STACK_SESSION';
const NAME_KEY = 'TRI_STACK_PLAYER_NAME';
const TUTORIAL_KEY = 'TRI_STACK_TUTORIAL_COMPLETE_V7';

// --- Sub-components ---

interface TutorialOverlayProps {
  step: number;
  onSkip: () => void;
  onNext: () => void;
}

const TutorialOverlay: React.FC<TutorialOverlayProps> = ({ step, onSkip, onNext }) => {
  if (step === 0) return null;
  let message = "";
  switch(step) {
    case 1: message = "Welcome! Your goal is to get your hand total as close to 0 as possible."; break;
    case 2: message = "Tap a card in your hand to select it for discarding."; break;
    case 3: message = "Now tap the DISCARD button to remove it."; break;
    case 4: message = "Every discard needs a draw. Tap the DECK to pick up a new card."; break;
    case 5: message = "When your total is 5 or less, tap SHOW to end the round. Good luck!"; break;
  }
  return (
    <div className="fixed inset-0 z-[100] flex flex-col items-center justify-center pointer-events-none">
      <div className="absolute inset-0 bg-black/80 backdrop-blur-[2px] pointer-events-auto" />
      <div className="relative z-[110] bg-slate-900 border-2 border-yellow-500 p-6 rounded-2xl shadow-2xl max-w-xs text-center animate-in zoom-in fade-in pointer-events-auto">
        <div className="flex justify-between items-start mb-4">
          <div className="bg-yellow-500 text-black px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-widest">Guide {step}/5</div>
          <button onClick={onSkip} className="text-gray-500 hover:text-white"><X size={18} /></button>
        </div>
        <p className="text-white font-bold mb-6 text-lg leading-tight">{message}</p>
        <div className="flex flex-col gap-2">
          {(step === 1 || step === 5) && (
            <button onClick={onNext} className="bg-yellow-500 hover:bg-yellow-400 text-black font-bold py-3 rounded-xl transition-all flex items-center justify-center gap-2">
              {step === 5 ? "Start Playing!" : "Next Step"} <ChevronRight size={18} />
            </button>
          )}
          <button onClick={onSkip} className="text-gray-400 text-xs hover:text-white py-2">Skip Tutorial</button>
        </div>
      </div>
    </div>
  );
};

// --- Main App ---

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [isGuest, setIsGuest] = useState(false);
  const [authLoading, setAuthLoading] = useState(true);
  const [hasSeenTutorial, setHasSeenTutorial] = useState<boolean>(() => {
    try { return localStorage.getItem(TUTORIAL_KEY) === 'true'; } catch { return false; }
  });
  const [tutorialStep, setTutorialStep] = useState(0);

  const [gameState, setGameState] = useState<GameState>({
    gameMode: null, deck: [], openDeck: [], players: [], currentPlayerIndex: 0,
    roundJoker: null, roundNumber: 1, totalRounds: DEFAULT_TOTAL_ROUNDS,
    phase: GamePhase.SETUP, turnLog: [], winner: null, lastDiscardedId: null,
    tossedThisTurn: false, pendingDiscard: null, pendingToss: [], playerNames: []
  });

  const [selectedCardIds, setSelectedCardIds] = useState<string[]>([]);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [showOnlineSelection, setShowOnlineSelection] = useState(false); 
  const [showRoundSelectionSP, setShowRoundSelectionSP] = useState(false);
  const [showPlayerCountMP, setShowPlayerCountMP] = useState(false);
  const [selectedTotalRounds, setSelectedTotalRounds] = useState(DEFAULT_TOTAL_ROUNDS);
  const [customDisplayName, setCustomDisplayName] = useState('');

  const [roomCode, setRoomCode] = useState('');
  const [joinCodeInput, setJoinCodeInput] = useState('');
  const [myOnlineId, setMyOnlineId] = useState<number | null>(null); 
  const [onlineLobbyPlayers, setOnlineLobbyPlayers] = useState<{id: number, name: string}[]>([]);
  const [isOnlineLobby, setIsOnlineLobby] = useState(false);
  const [isReconnecting, setIsReconnecting] = useState(false); 
  const [isJoining, setIsJoining] = useState(false); 

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setAuthLoading(false);
    }).catch(() => setAuthLoading(false));
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => setSession(session));
    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
    try {
      const savedName = localStorage.getItem(NAME_KEY);
      if (savedName) setCustomDisplayName(savedName);
    } catch (e) {}
  }, []);

  const getDisplayName = useCallback(() => {
    if (customDisplayName) return customDisplayName;
    return isGuest ? 'Guest' : (session?.user?.email?.split('@')[0] || 'Player');
  }, [customDisplayName, isGuest, session]);

  const skipTutorial = () => {
    setTutorialStep(0);
    setHasSeenTutorial(true);
    try { localStorage.setItem(TUTORIAL_KEY, 'true'); } catch {}
  };

  const advanceTutorial = () => {
    if (tutorialStep === 5) skipTutorial();
    else setTutorialStep(prev => prev + 1);
  };

  useEffect(() => {
    if (tutorialStep === 2 && selectedCardIds.length > 0) setTutorialStep(3);
    if (tutorialStep === 3 && gameState.phase === GamePhase.PLAYER_DRAW) setTutorialStep(4);
    if (tutorialStep === 4 && gameState.phase === GamePhase.PLAYER_TURN_START && gameState.currentPlayerIndex !== 0) {
      setTutorialStep(5);
    }
  }, [tutorialStep, selectedCardIds, gameState.phase, gameState.currentPlayerIndex]);

  const startRound = useCallback((roundNum: number, existingPlayers?: Player[], mode?: GameMode) => {
    const newDeck = createDeck();
    const roundJoker = { ...newDeck[Math.floor(Math.random() * newDeck.length)] };
    let players: Player[] = [];

    if (existingPlayers && existingPlayers.length > 0) {
      players = existingPlayers.map(p => ({ ...p, hand: [], score: 0, lastAction: 'Waiting...', wasCaller: false }));
    } else {
      const actualMode = mode || gameState.gameMode;
      if (actualMode === 'SINGLE_PLAYER') {
        const names = [getDisplayName(), 'Bot Alpha', 'Bot Beta', 'Bot Gamma'];
        players = names.map((n, i) => ({ id: i, name: n, isBot: i > 0, hand: [], score: 0, totalScore: 0, lastAction: 'Waiting...' }));
      } else if (actualMode === 'MULTIPLAYER') {
        // Default to 4 local players if not specified
        const names = Array.from({ length: 4 }, (_, i) => `Player ${i + 1}`);
        players = names.map((n, i) => ({ id: i, name: n, isBot: false, hand: [], score: 0, totalScore: 0, lastAction: 'Waiting...' }));
      }
    }

    players.forEach(p => { p.hand = newDeck.splice(0, 3); });

    setGameState(prev => {
      const targetMode = mode || prev.gameMode;
      const newState: GameState = {
        ...prev, deck: newDeck, openDeck: [], players, currentPlayerIndex: 0,
        roundJoker, roundNumber: roundNum, totalRounds: selectedTotalRounds,
        phase: GamePhase.PLAYER_TURN_START, tossedThisTurn: false, gameMode: targetMode,
        pendingDiscard: null, pendingToss: []
      };
      if (targetMode === 'ONLINE_HOST' && roomCode) updateGameState(roomCode, newState);
      return newState;
    });
    setSelectedCardIds([]);
  }, [getDisplayName, selectedTotalRounds, roomCode, gameState.gameMode]);

  const startSinglePlayer = (rounds: number) => {
    setSelectedTotalRounds(rounds);
    setGameState(prev => ({ ...prev, gameMode: 'SINGLE_PLAYER', phase: GamePhase.SETUP, players: [] }));
    setShowRoundSelectionSP(false);
    if (!hasSeenTutorial) setTutorialStep(1);
  };

  const startMultiplayer = () => {
    setGameState(prev => ({ ...prev, gameMode: 'MULTIPLAYER', phase: GamePhase.SETUP, players: [] }));
    setShowPlayerCountMP(false);
  };

  useEffect(() => {
    if (gameState.phase === GamePhase.SETUP && gameState.gameMode && !gameState.gameMode.startsWith('ONLINE')) {
      startRound(1, undefined, gameState.gameMode);
    }
  }, [gameState.phase, gameState.gameMode, startRound]);

  useEffect(() => {
    const checkSession = async () => {
      try {
        const savedSession = localStorage.getItem(SESSION_KEY);
        if (savedSession) {
          setIsReconnecting(true);
          const { code, playerId } = JSON.parse(savedSession);
          const { data: roomData, error } = await getRoomData(code);
          if (error || !roomData) { localStorage.removeItem(SESSION_KEY); setIsReconnecting(false); return; }
          setRoomCode(code);
          setMyOnlineId(playerId);
          setIsGuest(true);
          if (roomData.status === 'WAITING') { setOnlineLobbyPlayers(roomData.players || []); setIsOnlineLobby(true); }
          else if (roomData.game_state) setGameState({ ...roomData.game_state, gameMode: (playerId === 0 ? 'ONLINE_HOST' : 'ONLINE_CLIENT') });
        }
      } catch (e) { localStorage.removeItem(SESSION_KEY); } finally { setIsReconnecting(false); }
    };
    checkSession();
  }, []);

  useEffect(() => {
    if (!roomCode) return;
    const subscription = subscribeToRoom(roomCode, (roomData) => {
      if (roomData.status === 'WAITING') setOnlineLobbyPlayers(roomData.players || []);
      else if (roomData.game_state) {
         setGameState({ ...roomData.game_state, gameMode: (myOnlineId === 0 ? 'ONLINE_HOST' : 'ONLINE_CLIENT') });
         setIsOnlineLobby(false);
         setShowOnlineSelection(false);
      }
    });
    return () => { supabase.removeChannel(subscription); };
  }, [roomCode, myOnlineId]);

  const clearSession = () => {
    localStorage.removeItem(SESSION_KEY);
    setRoomCode('');
    setMyOnlineId(null);
    setIsOnlineLobby(false);
    setGameState({
      gameMode: null, deck: [], openDeck: [], players: [], currentPlayerIndex: 0,
      roundJoker: null, roundNumber: 1, totalRounds: DEFAULT_TOTAL_ROUNDS,
      phase: GamePhase.SETUP, turnLog: [], winner: null, lastDiscardedId: null,
      tossedThisTurn: false, pendingDiscard: null, pendingToss: [], playerNames: []
    });
    setSelectedCardIds([]);
    setIsTransitioning(false);
  };

  const currentPlayer = gameState.players[gameState.currentPlayerIndex] || null;
  const bottomPlayer = (gameState.gameMode === 'SINGLE_PLAYER' || (gameState.gameMode?.startsWith('ONLINE') && myOnlineId !== null))
    ? (gameState.players.find(p => p.id === (myOnlineId ?? 0)) || currentPlayer)
    : currentPlayer;

  const opponents = gameState.players.filter(p => p.id !== (bottomPlayer?.id ?? -1));
  const isMyTurn = (gameState.gameMode?.startsWith('ONLINE')) ? (currentPlayer?.id === myOnlineId) : true;
  const isPlayerTurn = !isTransitioning && currentPlayer && !currentPlayer.isBot && gameState.phase !== GamePhase.ROUND_END && isMyTurn;
  const isBotThinking = gameState.gameMode === 'SINGLE_PLAYER' && currentPlayer?.isBot && !isTransitioning && gameState.phase !== GamePhase.ROUND_END;

  useEffect(() => {
    if (!isBotThinking || !currentPlayer) return;
    const timeout = setTimeout(() => {
      setGameState(prev => {
        let newState = { ...prev };
        const curr = newState.players[newState.currentPlayerIndex];
        if (newState.phase === GamePhase.PLAYER_TURN_START) {
          const action = decideBotAction(curr, newState.roundJoker, newState.tossedThisTurn);
          if (action.type === 'SHOW') {
             const results = getRoundScores(newState.players, newState.currentPlayerIndex, newState.roundJoker);
             newState.players = newState.players.map(pl => {
               const res = results.find(r => r.playerId === pl.id);
               return { ...pl, score: res?.roundScore || 0, totalScore: pl.totalScore + (res?.roundScore || 0), wasCaller: pl.id === curr.id };
             });
             newState.phase = GamePhase.ROUND_END;
          } else if (action.type === 'TOSS') {
             const cards = curr.hand.filter(c => action.cardIds?.includes(c.id));
             newState.players = newState.players.map(pl => pl.id === curr.id ? { ...pl, hand: pl.hand.filter(c => !action.cardIds?.includes(c.id)) } : pl);
             newState.pendingToss = cards; newState.phase = GamePhase.PLAYER_TOSSING_DRAW; newState.tossedThisTurn = true;
          } else {
             const card = curr.hand.find(c => c.id === action.cardIds![0])!;
             newState.players = newState.players.map(pl => pl.id === curr.id ? { ...pl, hand: pl.hand.filter(c => c.id !== card.id) } : pl);
             newState.pendingDiscard = card; newState.lastDiscardedId = card.id; newState.phase = GamePhase.PLAYER_DRAW;
          }
        } else {
          const drawn = newState.deck.shift()!;
          newState.players = newState.players.map(pl => pl.id === curr.id ? { ...pl, hand: [...pl.hand, drawn] } : pl);
          if (newState.pendingToss.length) newState.openDeck = [...newState.openDeck, ...newState.pendingToss];
          if (newState.pendingDiscard) newState.openDeck = [...newState.openDeck, newState.pendingDiscard];
          newState.pendingToss = []; newState.pendingDiscard = null;
          newState.currentPlayerIndex = (newState.currentPlayerIndex + 1) % newState.players.length;
          newState.phase = GamePhase.PLAYER_TURN_START; newState.tossedThisTurn = false;
        }
        return newState;
      });
    }, 1200);
    return () => clearTimeout(timeout);
  }, [isBotThinking, currentPlayer?.id, gameState.phase]);

  const handleCardClick = (card: CardData) => {
    if (!isPlayerTurn) return;
    setSelectedCardIds(prev => prev.includes(card.id) ? prev.filter(id => id !== card.id) : (prev.length >= 2 ? [prev[1], card.id] : [...prev, card.id]));
  };

  const handleDiscard = () => {
    if (selectedCardIds.length !== 1 || !bottomPlayer) return;
    const card = bottomPlayer.hand.find(c => c.id === selectedCardIds[0])!;
    setGameState(prev => {
      const newState = {
        ...prev, 
        players: prev.players.map(pl => pl.id === bottomPlayer.id ? { ...pl, hand: pl.hand.filter(c => c.id !== card.id) } : pl),
        pendingDiscard: card, lastDiscardedId: card.id, phase: GamePhase.PLAYER_DRAW
      };
      if (roomCode) updateGameState(roomCode, newState);
      return newState;
    });
    setSelectedCardIds([]);
  };

  const handleDraw = (source: 'DECK' | 'OPEN') => {
    if (!bottomPlayer) return;
    setGameState(prev => {
      let drawn: CardData;
      let newDeck = [...prev.deck];
      let newOpen = [...prev.openDeck];
      if (source === 'OPEN') {
        if (newOpen.length === 0) return prev;
        drawn = newOpen.pop()!;
      } else {
        if (newDeck.length === 0) {
          if (newOpen.length <= 1) return prev;
          const top = newOpen.pop()!;
          newDeck = shuffleDeck(newOpen);
          newOpen = [top];
        }
        drawn = newDeck.shift()!;
      }
      const nextIdx = (prev.currentPlayerIndex + 1) % prev.players.length;
      const newState = {
        ...prev, deck: newDeck, openDeck: [...newOpen, ...(prev.pendingToss), ...(prev.pendingDiscard ? [prev.pendingDiscard] : [])],
        players: prev.players.map(pl => pl.id === bottomPlayer.id ? { ...pl, hand: [...pl.hand, drawn] } : pl),
        currentPlayerIndex: nextIdx, phase: GamePhase.PLAYER_TURN_START, tossedThisTurn: false, pendingDiscard: null, pendingToss: []
      };
      if (roomCode) updateGameState(roomCode, newState);
      if (prev.gameMode === 'MULTIPLAYER') setIsTransitioning(true);
      return newState;
    });
  };

  const handleShow = () => {
    if (!currentPlayer) return;
    const res = getRoundScores(gameState.players, gameState.currentPlayerIndex, gameState.roundJoker);
    const newState = {
      ...gameState, phase: GamePhase.ROUND_END,
      players: gameState.players.map(pl => {
        const r = res.find(i => i.playerId === pl.id);
        return { ...pl, score: r?.roundScore || 0, totalScore: pl.totalScore + (r?.roundScore || 0), wasCaller: pl.id === currentPlayer.id };
      })
    };
    setGameState(newState); if (roomCode) updateGameState(roomCode, newState);
  };

